INSERT INTO public.chapters (novel_id, chapter_no, language_code, title, raw_text, cleaned_text, structured_json, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message, script_json, world_model_json, format_detect_json, script_version, world_model_version, script_run_id, world_model_run_id, script_updated_at, world_model_updated_at) VALUES ('novel_b831875078b348ffa5569429fdb4105c', 1, 'zh-CN', '王麻子回村', '# 王麻子回村

## 场景一：村口老槐树

**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落  

---

### 【环境描写】

村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。

北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。

---

### 【人物出场】

**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。

他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。

**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。

---

### 【动作与情绪细节】

**王麻子**的脚步在槐树下骤然停住。

他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。

“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。

**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。

“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”

王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。

“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”

“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”

“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”

李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。

“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”

---

### 【冲突铺垫】

就在这时，远处传来狗吠。

不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, NULL, 0, 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 'default', 'default', 'tr_ch_ad9659f5a8fe', 'cr_ch_2cc1dfc72391', 'idem_chapter_novel_b831875078b348ffa5569429fdb4105c_1_e752f286', 'v1', NULL, '2026-02-28 16:39:38.922646+00', '2026-03-01 12:24:01.403715+00', NULL, NULL, NULL, NULL, '{"scenes": [{"mood": "紧张、不安、警惕", "time": "深夜，约莫子时三刻", "title": "王麻子回村", "actions": ["王麻子（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。", "李秀英（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。", "王麻子的脚步在槐树下骤然停住。他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。", "李秀英靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。", "王麻子蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。", "王麻子站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿。", "李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。", "就在这时，远处传来狗吠。不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影。"], "weather": "北风呼啸，乌云蔽月，偶有零星雨点砸落", "location": "王家村村口，老槐树下", "scene_id": "s001", "narration": "村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。", "dialogue_blocks": [{"line": "没人跟来。", "speaker": "王麻子"}, {"line": "有福……咱非得这时候回来？天亮了再进村不行吗？", "speaker": "李秀英"}, {"line": "等不到天亮。城里那些人……要是发现账本不见了，头一个就找这儿来。", "speaker": "王麻子"}, {"line": "可村里人……他们要是问起这些年……", "speaker": "李秀英"}, {"line": "就说在省城做小买卖，赔了。记住，秀英，咱什么都不知道。账本的事，一个字都不能提。", "speaker": "王麻子"}, {"line": "为了孩子。得让他生在干净地方。", "speaker": "王麻子"}]}], "summary": "深夜，离家多年的王麻子（王有福）带着怀孕的妻子李秀英秘密回到王家村村口。他神色警惕疲惫，声称因城里的“账本”事发必须连夜潜回，并叮嘱妻子对外统一口径称在省城做买卖赔了本。夫妻二人在老槐树下短暂歇息对话时，远处突然传来此起彼伏的狗吠声，王麻子顿时紧张地将妻子拉入阴影中躲藏。", "warnings": []}', '{"beats": [{"time": "深夜，约莫子时三刻", "title": "深夜潜回", "evidence": ["王麻子（