INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, '110dc566d850476f99f6a37ed8163e05', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342749+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '1c53a5edf0514659b8eddd123c8b0444', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342752+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '228a2ac77fbe42bcb5be8e310a83055c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342753+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, '2cd61bffbb9b49418399782b3b701456', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342753+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, '43c12f7163c3493dae2998450b53cb71', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342754+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '46e68c2a03dc4e4ead609167f769adb7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342754+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, '4e68552988d6479c8bdb987f81f72e06', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342755+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '562d45ebe6114d62aaccda35e114fef5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342756+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '5cf16ced5f4540ab96d1c33ed8edc1d6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342756+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, '5eb971d3b3e64aa9995e72dfe71c7e1d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342757+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '62071e1a3da94daab8aecf37a9327e4b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342758+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '6ea31b2e3b614c07b63127f5e0df0300', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342758+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, '716bf5e48941453d96c285623e5be4ef', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342759+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '717578e5b57a4851b6ad5a7c58c6efee', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342759+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '7a1f9815832a46ca94010ce182a05ee3', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.34276+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '945ca29efb5d4550bcbc5ecda2167113', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.34276+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, '95fbab4eedeb415986c5b04de4e86f99', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342761+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, '9d522376cc0f477fa8646ffdbdcd93a5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342761+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, 'a93b5d8a076f41848c1a6ec51623a468', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342762+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, 'ab28d4139ca4456bbd2ad6679193f882', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342763+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, 'b2fc325719e849a28a92206c2b2598f1', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342763+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, 'c1bc2604c5c044f7b2ba79453c1228c7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342764+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, 'c5edb1c5bf5c4a3d9c1bb24ef23be73d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342764+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, 'cd7aaf6ececc49aabf73c4b8c213c25b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342765+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, 'bdb892ab3f3647d88649287d59743faf', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454645+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, 'ce74ce6180a64c40b92fafa0bab16fcf', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342766+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, 'de2e24c6e5774a1db6dcbde2317df9f7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342766+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, 'ee11b600488d470cb27536ef1c651a37', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342767+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, 'f2ec3d9dce714e43960dd8afc483a6e8', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342767+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, '0c46abd4957d43e984be72dfdc1b777b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956362+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '2387e0efff0f4772ab74530994c8a543', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956368+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, '24bdc52dccc0430290a024400192802a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956369+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, '31109c63ad02479ea7c7af48bece7d3a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.95637+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, '3809ef0c1f53414e84bbbea053d113ba', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956373+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, '3af8fe52c5554d2bab561f021d503429', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956374+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '409797151f984ea79ffcdc23642c76bf', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956374+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, '54ec600d91ab458b9b442c5b1eba185d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956376+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '5657b0db041f44a09cc9e7e882560b9f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956376+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '6dd8e7e2c48d402ea336466bbc4f5e8b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956377+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '76d168960b574eb4a23f0b58cbcf6dec', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956378+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '80047440eb6c4eb295baa89d7f27656c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956378+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '95ad879317014b89a4aa19e011aafc90', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956379+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, '95e37cc86cdb408f922901688c03b75c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956379+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '98f5b1445ff049a18468d59fc778108d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.95638+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, 'af5a2047d4ba4f9a9e0f928423b205a5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.95638+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, 'af938a459f6448a7a6b36bf1527b6e46', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956381+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, 'b6b6cd45dcb841a29b49fb8731e57f12', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956382+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, 'bae65b8afe5247339042f3057bec03c0', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956382+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, 'bde06c88a1a54d43b37447674b437106', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956383+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '0067a3c1a55044bfb10487bf59b807ea', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:17.489948+00', '2026-03-01 06:59:52.128833+00', '2026-03-01 07:03:17.502286+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, 'bfa0902bed3642ec95e9e18b0d837070', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956383+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, 'c04e2751c6f34164af3c81538320354a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956384+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, 'c1e6da9ff0b346d49bd35e1874c610b0', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956384+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, 'd00cc9b78daf455b876d1b133777f47b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956385+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, 'd37728690f5f4590a5b0faed338592f4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956386+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, 'd6cab806a4a546d6883566ab85fd10a5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956386+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, 'e12866c851e04322ad09328522ec5e67', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956387+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, 'e5d9611db04c42bda29d44793d46605e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956387+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, '088d27fc492c4d21a14ce6c815f4b12f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:17.489948+00', '2026-03-01 06:59:52.128833+00', '2026-03-01 07:03:17.502293+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '0915c6be0d974bddbd701b90ca26a61a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:17.489948+00', '2026-03-01 06:59:52.128833+00', '2026-03-01 07:03:17.502294+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '1b14dea43b754211af916096a7b674eb', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:17.489948+00', '2026-03-01 06:59:52.128833+00', '2026-03-01 07:03:17.502295+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, '1d21781c6c6c446bb17e3673f0f1c176', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:17.489948+00', '2026-03-01 06:59:52.128833+00', '2026-03-01 07:03:17.502296+00', NULL, NULL, NULL, NULL);
