INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '41fba10c402e4d8f942ae97fd9747d3e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:17.489948+00', '2026-03-01 06:59:52.128833+00', '2026-03-01 07:03:17.502299+00', NULL, NULL, NULL, NULL);
