INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, 'c9056e2e36004e559dc88351f8e0ec2d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605788+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, 'db8c29f40e5a4e6d8351a059e1e70b8c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605789+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, 'e81425d96fa54a9ba1ccba29db9083ac', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605789+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, 'eec413d9f36b40429aefac851d0727a9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.60579+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, 'f1fb48a098794690b06fe882ab13e6b4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605791+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, 'fc24b82450264c0b83cb952793b71e80', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:52.391924+00', '2026-03-01 08:19:56.956388+00', NULL, NULL, NULL, NULL);
