INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, '9a20176c2ed04c27a63cd63a05b8d2df', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, 'f2e863ace0144b0eaee6d42f9b262efc', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '8ad72c6aa0024741a9230fca6dd4f434', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, 'c836e8ff7d2741519da680a14b7e7857', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '5c10bed6f3e64d0e9fbd64e6bb5d3bf6', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '4bec7e5c8db841388bde33573a46e29c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, '528d78d7775a4a0b9f163c58ce6f25c9', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, '1b81c3989f90431a9c25a27111a02061', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, '4d9412d1ca1c41c088dd6907d7f451b0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '769f74def4024f9c9c80e969caea25d8', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '67d73af07cde421bbf6b76e5cc323287', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, 'b844577a2f1e4caa90fc81023da4db4d', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, '37d3e560d7ca4b1f821c3652ffdb1e20', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, '0cefe182e2944503bb7d0e370102072f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, 'fdbd11389ceb442b9f4a415640363c64', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, 'f92eee62f63e419db4dbe23f8f17146f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '02c6fe041aec42539fb07c12c09c03c4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328772+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '0b8d9f36ba9142489738d5426da2f9d9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328778+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, '1d1668ed45fe4f71a4fbf356401fcf79', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.32878+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, '26487135491a400ead3f46e3ac58eeb8', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.32878+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '2c2a3f6871ed461b9776950d7f31aa5b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328781+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, '30374df2f776411690c73b7b53437ecf', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328782+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '4ae0db4897634493a59cfdecd0460916', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328782+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, '1e66014781e24582a4f27ea45fae686f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938836+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '52eef1edb15b4789baf3a48c047d2a45', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328783+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '551d2edc098640fa909d1f52dc4cbdef', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328784+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, '5d960225c8fb4641b0e497a5211d8d01', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328784+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '5ea596714a4c47fa9860b3282bc2858a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328785+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, '66d27d370a8c49ca9e3a4c5826c78fe2', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328786+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '6a6b57a87eb34b47811c721e7f243205', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328786+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '6c6f6ca7de184ec2a54c7a446578c782', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328787+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '718fe2ed869a405fba23f17177cffab8', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328787+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '9aebc76b7e084ab38b0cbf5074e707e8', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328788+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, '9bd05f47b19a43099d4d9d06f4f0011b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328789+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, 'a30a4f2e6e5f456a9d71055549c57694', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328789+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, 'a42b882dbd8b4112956cd87948178629', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.32879+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, 'a8528bee8a0448e5aac34d8a1144f994', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328791+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, 'ad00b562e28040f8a1093fc26aceadbb', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328791+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, 'aea06819328244a79b963c1cb538d4ac', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328792+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, 'bf1b009f0d6c44ddab5701924367c5ec', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328792+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, 'd29978bd6de74797af65e1b7bd8a66c1', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328793+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, 'd701f597808a46e4986270a97b95d5a9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328794+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, 'e505b7567ba24e6f8ef8fafcf2e1979d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328794+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, 'f48e6178f0344866865591fd303f3a47', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328795+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, 'fde5839f4d9c4407a72d1b015e9c935e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:03:17.489948+00', '2026-03-01 07:03:19.328795+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '60228dda4e3c468796615da113635f1f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, 'eb97e809bbd64ffeb7059625fcb78fb1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, 'be8591ced51d4aeb993eceee7fd2af31', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454645+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, '0cb28528259e45dca51337d9a10d8fd1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '76016b170757458e8d9160cf99d9551b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '9a5809ddce9145909ad5a94765c55448', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '014b1bf4a73a4e7283706f3d3c8308e7', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '3aa8ffd815d8403a87f3dad9a2daba2d', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, 'a21ba82699e94437ace2372a7f50fa49', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '14c92515439f457bae25b35949c6b0ab', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605766+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '16740606733e4be9be2dc9b4a8e21b7a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605773+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, '38866f1678b64b6983c7a8299c8c7caf', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605773+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '4d634e8b1b3b40c892045641dfacf0ad', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605774+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '4e87d194a7a34bdf8e59aa889317bd0a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605775+00', NULL, NULL, NULL, NULL);
