INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '650204b641574c8686c4e001c92660a4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605778+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '6c8b92baad134969a4da35757deb9362', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605779+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '704f203308a443d2adf104c44a790afa', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.60578+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, '728e43f865644e729bb4e51adeb51035', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.60578+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, '729b232f18594dfeb1f99e9c59a58bc7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605781+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '81192ded3e654e189a57d2c6e8f0088b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605782+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '8a49598d3b14453e9b1178ce79ca9cd2', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605783+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, '980e5d4cbf7b4b97a38d43f4f19fbdd1', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605783+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, 'fff8d42d9f004a08b121323220c52b11', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 07:08:37.591804+00', '2026-03-01 07:03:19.321748+00', '2026-03-01 07:08:37.605792+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, 'fde8830436454284a835b741598bd765', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:17.923937+00', '2026-03-01 09:28:45.342768+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, 'a002436f974c4c179a4c5e8ce52cba5e', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, '25106b23b9d94136a365afe50a71c966', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, 'eb3e89c7022842a999a0bedf7f4fde9b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('844b6f92a6874930b7e7a09e2f68d350', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, 'a09e2d15fdf3460e9f8cc06fbe2d6238', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:56.941819+00', '2026-03-01 08:19:56.941819+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '0514ba3f668040e1918ac2b24438842a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:37.591804+00', '2026-03-01 08:59:01.422063+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, '07b85c7cd3024945babf07b05b9c8a82', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:37.591804+00', '2026-03-01 08:59:01.422069+00', NULL, NULL, NULL, NULL);
