INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '51b87f5e96714fe5b2fb821b7ef04ada', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:37.591804+00', '2026-03-01 08:59:01.422094+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, '53b352c099c643cdb4b57bcadc8dda01', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:37.591804+00', '2026-03-01 08:59:01.422094+00', NULL, NULL, NULL, NULL);
