**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '1bf029e638684e2bb57cadc1c8b23fd6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938835+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, '0c06e8a943604ff591b97b899d709e12', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.63075+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, 'b4fc767e8c3445c894e3b09eacdf8336', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, '3b6420404d434f5fa95369b827e807b0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, '07ee456936a44231aa09a1ee4716262e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.45463+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '08be992b99b64e31a3efbc57cd906cf4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454634+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, '0fd61944b0f344e0ad59f70ad245c626', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454634+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '1b2193e90e0444bbb975c0fc85edfca9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454635+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '25d2e7a6d4dc474a88db6ff773502e22', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454635+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '2da567439ba54aca9b4671ade5ce4699', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454636+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, '470df4387eec4cfeb9b6812786528674', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454637+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, '47db9b78e22b4e69ba9b5a57ff4b98ad', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454637+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '47fa10e8f5cf4d8583a5fe641d03574d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454638+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, '509a35cffeed4034bd3bb73b8532c64f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454639+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, '5662996fad314923a110055c2139738f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454639+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, '569e04e3a5384941b348de9ae6154ff9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.45464+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '630fbdca04364b2c8beeae7a56c05c15', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454641+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '688b7c7bf68345ea81476a26ba9a4021', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454641+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '877f04512a8849078e3c8b8f591558ac', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454642+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '92212c83c60a494093b819cae1caf82b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454643+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, 'aceabe64629f4879accdff5e326042eb', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454644+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, 'ae11944fa49149e392af8a627b5e1f59', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.454644+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, '17e06ab4802b409882e5051a461f72b5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938831+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '29f0b53410004f00acbe41ff3a85b43a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938836+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '3244b2b7cc194e448fe373ad0d8f6475', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938838+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, '4088e8470ba747dbb2661023d249f9cb', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938839+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '5aa96d4d13194a91af4161ff89ed7d4f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938844+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '5ad82ac458214dbb863c02588c98bd95', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938845+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, '36fc57335c6b4a66858b1e66557fe451', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938839+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '634a5f156e7448568844495f82e91e0f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938845+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '638d71b8fc16490283f1b1ea1768d556', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938846+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '64d2cb96f09341ad9a9bcccb5acc872f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938846+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, '92df1109339244c1967eb5a357f3da2c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938847+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, 'a16676a3af664e769cb107ff19154ec5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938847+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, 'a3e48492f90a47eab9819cfefef95234', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938847+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, 'ae65508a60724e45ba4a3892a14dd23c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938848+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, 'b098a5c686b14fa8b363524f894abdef', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938848+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, 'b8bdbb990eb047ca89c753c7aca15a8b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938848+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, 'c1aef2b30db94ff5ae0f14f169d7dedb', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938849+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, 'c528cc8bb5164513bddc2e594c3d4714', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938849+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, 'c94fa15946484ebdb957756e35c07df8', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938849+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, 'c9677edb07774f72ba46aabc6f8b0206', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.93885+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, 'ccc2d7fd6b0b4d95b843a6dcd46b6aab', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.93885+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, 'd96a85368daa4bc38991dc431ca16c0a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.93885+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, 'e0610617dca04da8b6991c0741b2e82e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938851+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, 'e24569c318ef43a6b44ad8eda4c7024b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938851+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, 'e907f227285e4f578efdc70209a62d7d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938851+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, 'eb8bff5955804147b10cfa299d03af41', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938852+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, 'f1ed51a8f52c4c269e15853babd98433', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:01.407356+00', '2026-03-01 09:23:17.938852+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, '0ba32158c6c247d9b894008c6ff00495', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695754+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, 'bfa76d27b7854e82ad2af5ab70063f01', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695763+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'action', '王麻子站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿。', NULL, 0, '3c0359bb0b734ec2a0bcf45a8d6b48af', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'action', '就在这时，远处传来狗吠。不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影。', NULL, 0, '4679bf3fb6994b9786cd97d66640c7b5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719053+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '09624f885d85461ebff7d53b10e6e962', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.69575+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, '14fb4a05e5c94a8d8a64c329e8a31711', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695755+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '185f8eb7be41416eba4d2efe20e249d5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695755+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '2dcdb2f9a6094c289cf8832908da290c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695756+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, '2eb2f254609e4cc88f702429db39ecef', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695756+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '3227d345468f429bbdd05d1ff4efd4fa', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695757+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, '338325c584d74c509f5363c91089f729', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695757+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, '36f186d6db454d22a7ce07b3dbe2e06d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695757+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '402c50bb96694b2b945c488fbfbddab4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695758+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '4711bfec037d42ac8e8d1fb7fd31c7fa', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695758+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '4c1543599c1640da8253f8bb8fd4970f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695759+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '5456fadf3b5c410a9fa701c52088e099', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695759+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '85e178b0b7994600b79c3dbc3bc39ee3', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.69576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, '8a2a6bf13a1f4774812c24ff3685a460', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.69576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '8b20f8d7af8845f29c797f32f698e251', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.69576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '92e9746b570440eca058726a434e4f1a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695761+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, 'aa98de4304f946d284044e5d51224f65', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695761+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, 'ac49a33f7ee04e1e86b3a17377cf59fa', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695762+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, 'ad2ccc1dba6747688a107135d04b3a8e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695762+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, 'b5f5acbf1c2a4d628f284b2debf40547', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695762+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, 'bc69fefd64e447898f900ebb77ac4918', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695763+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, 'caf0da8a3b00455f9eec26b2c5a68602', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695764+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, 'd0cddb54031c484e9a95b3e7a32641c2', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695764+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, 'e9e527609d124a1cb39e3832ff0f7c88', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695765+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, 'f5fb823413894612bf907d288e951096', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:28:46.45465+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, 'ec4a55296739430a8f5639905dfb1c1f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695765+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, 'f11d8502f9584a56b14e18ccfb8744d7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695765+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, 'f27ab971c99045c98780257fa4541f86', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:10:43.643649+00', '2026-03-01 11:10:52.695766+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '0b039b8915bc4401b8f8263bcd4e4532', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.63074+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, '17e3a32cf333405aa33c788a4927f529', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.63075+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, '4778de741925435b9c8e72530384840e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630754+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, '4ee9c15c18434b24920d8484f091d7ed', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630756+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '555c295a91234a43a077deda2e469c04', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630756+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '74941dea9acc47c6b834465ad01594fa', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630759+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, '76a645f213cb42c89b2bca5bcc586112', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.63076+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, 'f951d2164b244a61aa68b1dbba28449a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630764+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, '0c8beb4c39ae4355ac0ca2c8331933e8', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032278+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '2108adfc58bd4f92a0e315af41040626', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.03228+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, '4c46a1e0834043fcbe78d79b8b26ef1c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032283+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, '55a3bf5c7770435ea149f16c410462e8', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032283+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '68a470a04fd04e3ea50851d31145b22a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032284+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, '6a29a9643bf44f7ab72e2f7e13a4d4d6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032285+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, '7aa5a5a87ecf4813b00228e7178668d2', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032286+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '7e51c3fb060f41d4bfbafe698760b990', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032286+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'dialogue', '王麻子：等不到天亮。城里那些人……要是发现账本不见了，头一个就找这儿来。', '王麻子', 0, '48460912e46746efa1fac4cd1ec7e060', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719053+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'action', '王麻子（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '550d825ad40349e3849605fa11752f3e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719054+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'action', '李秀英（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '6137706546a442c7bbc4862c21ed93d4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719054+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'dialogue', '王麻子：为了孩子。得让他生在干净地方。', '王麻子', 0, '8774eb1c45ba4638b8c357d4167bfd95', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719055+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'action', '李秀英靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '968e99ce70ee428fa215066613ec7b08', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719055+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'action', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '9c3a32a7bc9342aea62b4edf82b8bfe1', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719055+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'dialogue', '李秀英：有福……咱非得这时候回来？天亮了再进村不行吗？', '李秀英', 0, 'b78495a1817e410abfd2b13aaa8e150a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719056+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'dialogue', '王麻子：就说在省城做小买卖，赔了。记住，秀英，咱什么都不知道。账本的事，一个字都不能提。', '王麻子', 0, 'd9142d9478b645f49c592497ed1e868b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719056+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, '34c19264a99140c3afddc01e4ca88a87', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630753+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '3d7b4dceba604065852ddb8f69e86ed0', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630753+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '4a35c02b2f4a45719603f038baade920', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630755+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, '4b6e6b44e09f41a684249fba70f81ae8', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630755+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '5ad71c0e3e784a9a8b418cd22cdc18ee', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630757+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, '5fa244514a9b41d08b073770b8c49c44', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630757+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '6246ce17c5654808a355ddefe5aafa04', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630757+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '6b49e0dfcd924eb19300e63f34b9d6be', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630758+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, '6dfdab7e4d7c44e5b2b1533a92b0bb06', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630758+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, '6e90febacb3947bf81cbfb9f4836a626', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630759+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '790987daf5b947ef8a943e51c48c0f03', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.63076+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '80704e5e24f64508831a4c1527ca547a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.63076+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, '92c60773d9304fd2af77821e72c2e93f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630761+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '94a34efe79b64c33a398f8586c4bbd7c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630761+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, 'b26d1495254340168a0e8fa4c6c92dff', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630762+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, 'd8585989aee84e14a20788672432aa41', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630762+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, 'e7398c95d6a54ba2a8e6308c5d08c197', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630763+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, 'ef0125a23809438d9447d1ee40a7e6e2', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630763+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, 'f2e5f6ba9f66469e9e8219f36a3a79ea', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:46.450003+00', '2026-03-01 09:44:15.630763+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, '7782e0dd274a45d79621080fdd975570', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
