INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, 'c09eff4c392b4513977230b45a10c0e3', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, 'ce261a25e5564582a7bc886071e6a27f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, 'f94fdc76961647b38f4c9b78b8c578ef', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '3ca481832609422ca3736e789a43400f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '4f414dc77dcb41d8abb5d2504a9d3048', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, '0758cbfa236344eca77f48fd7f57681a', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, '2fd6980f93a647318a1b094d300d3f77', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '5b2608e6985247f3a109df7bde222f16', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, 'a2780e1ff562403ba0e97d2d02202914', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '215029367fa548929888509a5d26ce44', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, 'e9296fee4cec4307a7bb73790b1e9ff6', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, 'd71be842f5eb42129a516d66d69461c4', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '6df91f90144f4a1caa7f2e23576086fa', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '441b8a1d23a14dddad19218e7ee9d666', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '69ce5804899c4b4d8e75d623c65b201d', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '4a112d00ec30458f8447a60e63189f62', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, 'ca25221ee5504ef78e2667bb22615a18', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, '66a7acb7783d4fd0a2d434200e9cdb08', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, 'a48cfd1dc46744f489080aaff6dfa944', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, 'b1f2e49c28a04170a03f55fc9b7336b3', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b862f0a472084a77beab20538052ac2e', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, '0d67fca4ece54edc8f7c09619b3a8aac', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:15.611576+00', '2026-03-01 09:44:15.611576+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, 'f1d540ee25404e61becd52719e393004', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '60ca4b20a2bc47909531162bf9cda64b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '86165587ad9a441ba71247080be79988', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, '6972c5993ea340959cf4e55fcb266968', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '834e3b5a05dc4b74a3089b7cd26f0158', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '7cff9fad02a0460389befe8e2749f16b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, 'c55f37c422df401a91bd19f3bd952edc', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, '087f3b48a38b44a4b6ee80afd54e2ca0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, '1e7ad710fd3c42648cdda01dfb673803', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '392ffe3b32f34228ab64b9f53b3ec84a', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, 'e4b7fe9352784ea180159a0982d96eb9', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '60d2a90749964bfeaf707a03abeb787f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, 'd32c48d846f942e48b16687628854cd9', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, 'd862091194fd4179be443bf53f5e6d51', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '58dc42bc21924610a484cc6dc06a4454', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, '303b6681b43c478288420d061eeb9234', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '9abff49263b84edda3dc7a15609c89b2', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '9becd09d873646b7a19bd13bce66b56f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, '13bfbec26f4c4611b592246530d03a9d', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '52d31d3d241b44448a5af5a352772551', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '7ba9d568ac664476a6f0f9894a680de8', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, 'ea7ded8a69e641e789107ff531bd05f0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, 'af868a445ae14baa955fdd1d822dee64', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, '7566be3045424a1a93bc582bbb1942aa', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, '9b47bdb6049541ccab634f83777b8407', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, '5c024afad5de403f95fdd5b1b05ab7af', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2312e0a93a6b4c8da66e19f864632e1b', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, 'f7fbe563574944e2a2bb136b79b5d4ff', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:43.645513+00', '2026-03-01 09:47:43.645513+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '040061a6d5f64371a21b8638f7c0cb4b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032271+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, '0f387c88a1654fdbb848b23c88738fc2', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032279+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '2706f1357bbb462ba7604000072d9bf6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.03228+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, '2a4cf7c9527b448c993d049fbd304264', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032281+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '2fa239e8e8c74bd3af74b874e9ef86da', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032281+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, '38436939162546509332196320601b47', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032282+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '56fcc4613b404a37b5b3795f6dc6e0ca', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032284+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '71082fee213f4864b7ca24f7ea1e49e9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032285+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, '72431bcaf40f41a281f924bd839d321a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032286+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '7f7d4a32e8b84a509deba4617a7d6441', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032287+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '8437b34f5c8d450dbbcf707aab509b55', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.03229+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '8b66446dbf13443d8922f73869eedb4a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.03229+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '8bacd94b9e6c441895b07b28f240dbe9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.03229+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, '9dab901844b44473ad8c6ea3bf8667c7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032291+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, 'd2792fed4908481eb0e265616c69179e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032291+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, 'd395f297fe8b4e86bac8a7bfdac8d820', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032292+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, 'db2180c49fd645e192dcd2238d569bc2', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032292+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, 'e06b5faeca2d45f1bc9f92d4945cb540', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032293+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, 'ef22ceb60d2f46c08d8fffd91a81a551', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032294+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, 'f194c635d6274c6c81715617acd95653', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032294+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, 'f81dc6bc526e4f429d3129204ad24366', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.691044+00', '2026-03-01 11:13:44.032295+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, 'c20f6ec8654342f6a3918e9581d6eab7', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
