**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '6bfe63396ef544a49369d2f20d6eec0a', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, 'a5c96dcf985d4a4697a92513f41d37a6', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, '9546c8d7a3d04c1c95cdd0ea1cabd7d0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '487b64be1b44437ab2e8568f8243088f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, 'f10a338f3f424d0f989d42ed743d2da2', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, '7457436bd4904ee986e62fd902c0e2a1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, '0025141f460d4f69ab3cf226546410a2', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585877+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, '04f9fd3bad2744598d79c4b309f6d637', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585896+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '0837e4b94ec74da9b303346d61aacb7d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585896+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '0d648b2945764181a71b0b880bf760e9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585897+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, '0eaa870bd25f4a57a7aea5076df9d9d3', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.5859+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '18191ff6a3d543c7a5dc0496d5b20d20', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.5859+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '1be6a18943274c3e97437deec17bd32b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585901+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, '3f62181673214e208e3f80a7bfdc6b3c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585902+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '59cfff052a424d29944c99a3cc0ffc9f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585903+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, '626dc910ee7e496d939bcfc2a8827a72', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585903+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '639ee24af6284488a493531d3e83bd24', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585904+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '6bd060d018bb46699a9f23cd04351c97', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585904+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '75829bbdcb494f6eb042edc93108eeb9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585905+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '7a5a5b5905d8426aad71ce518d3a4de6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585905+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, '7a7701d657c44db59f3ccc6130f20606', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585906+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, 'a48a3d66f306465c8d96401716340ba4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585906+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, 'afe39bb64ae643799db00f5598f9a65a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585906+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, 'b2f426c3dd6b42af846fe01f149f7b6e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585907+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, 'bc0c2e4c4d1b4545bd58e324dafa6c23', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585907+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, 'bcdb5eeac7294776aeccb2f46f76c537', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585908+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, 'c3dd51e0766a48d0b872653a65bfe6f6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585908+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, 'c3f616f47dbd4c5da4129085a299a6f0', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585909+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, 'ccc8c29fc2684cbfa720df9ccf732904', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585909+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, 'ccfa34753be642178b6f1643447087b5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.58591+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, 'd04a801a2d66431db5fe17a62e328d99', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.58591+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, 'd2062c56aed04a41b65fa8e207ca4a5b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585911+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, 'd68d25ea6416463094ed65e9b2dc99eb', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585911+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, 'e51646e7700a477790a1636c005aeca6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585912+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, 'e545c92ba0d34ae69b8c503f561c4d67', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:50.367673+00', '2026-03-01 11:02:30.585912+00', NULL, NULL, NULL, NULL);
