INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, 'eb4b63c9cc6147d3b4169d85c0bae60c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '7be010654f27432081aebefaeee54a33', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
