INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, 'e5144665d1f24b779e2735b555537106', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, 'a9da93d13b4f43dc95163ae727a50735', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '2e32f642265c46738c243daa777360b1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, 'a6b5980c128f41d0a4b30b720115db57', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, '17cd8dae9f8848e48e4fced8a8db8b74', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, '3a03133ef8af427caf25dbfbe164746f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, 'bea0a8dac04d4211b7b97502cb7ebd6d', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, 'de290e24a76649f6b7bcb2e8ccb98814', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '7784c27a613d43dc960fd36251f4ea22', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, '8345e71b5a15418bb408fd20461cb124', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, '34a25d4a136a42b9b640e61719604860', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '68bb9d97082345c69cbcaec55d9857f1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, '2533b16c67c64ccba6ec60e2a2fe8634', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '91d9baa34a564753a02b554b95e06166', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '1259362ecdda4a2585eedd16ebe1de9e', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, '44fb19005edf49d9826cafa59d957dad', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '74dbead94cc14991b00acc1f1a5ae3cb', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '435d41ba84a6460c84a0b98c7fe3b3d1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '91003384d94a451396b2a84756e3cf06', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '640633a3313b4406ba3c3cbef581e0ef', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, 'da5520ff1ddb4a3e8249c6a548e40ab1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, '58a8c613c86a4beab5293a2b84259858', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, 'e84a88bf793f44dd980a0f4c36e41294', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, '343b27f6981841289a35da64b159987b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b99582ef92864d0dbc119d4ac347b087', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, '1d5053c4c8df4700b66c8f369ee2f9a6', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:02:30.57455+00', '2026-03-01 11:02:30.57455+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, '0f44c0eb452c492ba6832ec4de69220b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, 'aed22a6572f14d06b8c435f2cf069173', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '43f7ad81d8914fe3a18b2efaf71e8fa0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '157dc29738a54808babe82aa14540b3b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '1dbfd840eaf843058c00f375932fa6a1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, 'b3c1313dc6b2481ba0ce6fa31297c8f3', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, 'e3cfbae8b54e41e180db6edb94197fa0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '1ef97d5d4e9f48b39b5bd50011f4a81a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385693+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, 'afaa3fff0f3f4da2ae40f66113d80d34', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, '99549f67bf1145818db3071cfc58f23d', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '77c14fc75d4942c6a278b04392e69837', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '1e9919a065904e7ab39869c84a03d46b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, '2fb4ceb1c0254eb28367404d59254c32', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '2378484f012548dcbe21ef4700f469e0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, 'f1cee4e9ee334a479fea130eb5eea1e4', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, 'aaee57863cd742d5a0ec94d5837d9c9c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '1b901d7cd7c648f39d6fff11a589cf90', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, 'ad00b05feace4b10bcee6cf20ff87174', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, '924448c418d14ca0ad545096e002d651', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, '52e105366a1d41e8a5ea40af209244b4', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, 'a2156e297c924bbfb4f49f71348551ff', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ada3637a24de44db91c1359958e586a5', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, '6060a93e1e144493b5cd4be31cf47af1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.025052+00', '2026-03-01 11:13:44.025052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', 's001 | 王麻子回村 | 深夜，约莫子时三刻 | 王家村村口，老槐树下', NULL, 0, 'e4aba8a8f3d74043b4d7b779845a52d7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719057+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'action', '王麻子的脚步在槐树下骤然停住。他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, 'fd5739eace4c40bebb2aa00cf2d9f4cb', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719057+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, 'fe3d7453cf594cf58ddaea0643540c8a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719058+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', 's001 | 王麻子回村 | 深夜，约莫子时三刻 | 王家村村口，老槐树下', NULL, 0, 'd57cc3a2198f4f7ab59e8557ecebe580', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649049+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 25, 'scene_break', '---', NULL, 0, '007fea71a690421b88dee21949e8ee92', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385687+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '1175b61b4d0b442e982cc2a00b82d476', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385691+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, '118660bbab234dcbb729dcb24632d14c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385692+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '12020c3ef68a40e2b4fc4a29ce72db51', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385692+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, '24ae02cc2b354bc79bd71862873d2779', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385693+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, '24e81160dd8449a298d7aa60bc421b94', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385694+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '258e658ae04040a99c9f2f435f132740', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385694+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '4690de1cb8dc412f98a3b7c9153f0773', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385695+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, '4e1cc98a19ba4d6681550660db3e4fa7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385695+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '5680cc119d624ea99b196d8f7b744abd', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385695+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, '5df6fcc6285c4463b574c40e756af410', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385696+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '6b2004193de940fb98f640a0240f438d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385696+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, '6b2a608bc72a42f9afd3faeea5b0145c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385697+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, '6bbdcf8cd85749c0aef07503fe0d922b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385697+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '853ac4bd56cb4d19bda3d3eddb76d981', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385697+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, '8a25e3c9fee84b908c2824a91d38606a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385698+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, '8be59ae7135f49a6a1edca5a20b7c91e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385698+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '**时间**：深夜，约莫子时三刻  
**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, '8c5a849a562942f68bd20170a72c5727', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385699+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, '9100717321f04c568a978f495d0592f9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385699+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, '99a21f3a61de45c0bb6ada944ee83872', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385699+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'heading', '## 场景一：村口老槐树', NULL, 0, 'a9914d7185d64efeab725870942ed450', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.3857+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, 'b874312487df4b2daf805f2ef70b911e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.3857+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, 'b890cb6d57aa4cefbd3fc0638e19b3a5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385701+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, 'ba12aa972acc487bb4c166025ffd68c5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385701+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, 'cb3b32ad5a70443598cee4068f26e956', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385701+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, 'd2ae55fac4994dd0965794c6414ad3d8', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385702+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, 'd48ab1c2afc14922ac22f6ec31fdfa1f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385702+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, 'ecb0306e301f40768c7ebec3fbee8b00', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:05:00.375952+00', '2026-03-01 11:04:00.463435+00', '2026-03-01 11:05:00.385703+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', '# 王麻子回村', NULL, 0, '30e2ea0eaa294dc3bd47b2674cca77ed', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
