**地点**：王家村村口，老槐树下  
**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落', '**时间**', 0, 'b3e7363e38c24e06b23e3b27c85be00c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'scene_break', '---', NULL, 0, '2b4ad98398504763a8bdab1810c8b1ce', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'heading', '### 【环境描写】', NULL, 0, 'cb6f27454543424e9e84e48f5c79e83a', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。', NULL, 0, '39d2734fa0ff49f6adf2987e7883a1f3', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'narration', '北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '377342f144ff42ca9422288ddde8e43b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'scene_break', '---', NULL, 0, '6f5990c2bc754d1d9f52ab241d5e72af', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'heading', '### 【人物出场】', NULL, 0, 'ac615910a4b54d1ba892e20ec2310051', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'narration', '**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。', NULL, 0, '22859b30ecbf4cd8b3458e2e1637da7f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'narration', '他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, 'fda44fa541eb485b8d94ea7b722c3ef4', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'narration', '**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, 'd047adbb3dd94660b409872b7504c2c7', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'scene_break', '---', NULL, 0, '76798f9ef61f4beaacb093429da42519', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'heading', '### 【动作与情绪细节】', NULL, 0, '1a6567d5daf3427092de3e3004a44f95', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'narration', '**王麻子**的脚步在槐树下骤然停住。', NULL, 0, 'f99f662f504a4848a4309d899b9e5f79', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'narration', '他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '9296aab4d7124ab0bd27c56165a03482', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 16, 'narration', '“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。', NULL, 0, '4f41fab1040e4a3485df18deed12d9ae', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 17, 'narration', '**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, '52cf19b7b91f413eb6565c261a18307f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 18, 'narration', '“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”', NULL, 0, 'fca0af8cfb62441f87790660c6055dbe', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 19, 'narration', '王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, '35c33801cefb425888072fb387d25a01', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 20, 'narration', '“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”', NULL, 0, '97e1220b43c94d9dbc669cd74e6f3147', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 21, 'narration', '“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”', NULL, 0, 'b452d325457f443b82a1d541304af747', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 22, 'narration', '“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”', NULL, 0, '355c13bc0ed44ca7b5abba28e455690f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 23, 'narration', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, 'f625be7483c3401293f1171fc03e31e1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 24, 'narration', '“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”', NULL, 0, '1d8e6e2b6cff40fc9ef26f3452f87240', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 26, 'heading', '### 【冲突铺垫】', NULL, 0, 'b0b201ccd9634dc1bc5afe73dbed1052', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 27, 'narration', '就在这时，远处传来狗吠。', NULL, 0, '17f8970d71ba44b6b9e0d659e2077682', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9f584c4c4c964c0cbce831b5c884d1c2', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 28, 'narration', '不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影', NULL, 0, '4bae5f3a9a6145d2b707cb1eb9b7c719', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:05:00.375952+00', '2026-03-01 11:05:00.375952+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'dialogue', '李秀英：可村里人……他们要是问起这些年……', '李秀英', 0, '10f637f7352348199cc3bf4e37da7323', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719048+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'action', '王麻子蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, '26fb72be28db46afb823170911b90456', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719051+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '王麻子：没人跟来。', '王麻子', 0, '2ba783aac3db4a0ab31aabb0d94a0508', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:18.702421+00', '2026-03-01 11:59:13.449289+00', '2026-03-01 12:16:18.719052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'dialogue', '李秀英：可村里人……他们要是问起这些年……', '李秀英', 0, '001771e9fffe4af19ecd4170152a2e08', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649036+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '王麻子：没人跟来。', '王麻子', 0, '10470aa576ea48f5bd0d8960a83b9f3a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649042+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'dialogue', '李秀英：有福……咱非得这时候回来？天亮了再进村不行吗？', '李秀英', 0, '1933d0b240804e65a64bdc00f24e9120', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649043+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'action', '王麻子的脚步在槐树下骤然停住。他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '38331699cccb4f2c9054c297c402649f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649043+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'action', '就在这时，远处传来狗吠。不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影。', NULL, 0, '3c3dec5f14b1473fbb868cfdf0b3ed02', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649044+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'dialogue', '王麻子：为了孩子。得让他生在干净地方。', '王麻子', 0, '64f862a0897e4fea8e796ef851a8c890', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649045+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'dialogue', '李秀英：有福……咱非得这时候回来？天亮了再进村不行吗？', '李秀英', 0, '3f72b280e73c483fb51464b8dfc13f52', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416478+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'action', '王麻子（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, '55f5664147714bcc8fcd538db000d6e4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416479+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, '7dfbaf6f1c9e423288ef8d2e0bc797f9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.41648+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'dialogue', '王麻子：等不到天亮。城里那些人……要是发现账本不见了，头一个就找这儿来。', '王麻子', 0, 'c176a737e2c448aea575d9f3d085fa9a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416481+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'dialogue', '王麻子：为了孩子。得让他生在干净地方。', '王麻子', 0, 'd4c40b678ad64e3582997b38b4ed5aa8', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416482+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 2, 'dialogue', '王麻子：没人跟来。', '王麻子', 0, 'eef84b1bba3f4594a9990532995851f1', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416482+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'dialogue', '王麻子：就说在省城做小买卖，赔了。记住，秀英，咱什么都不知道。账本的事，一个字都不能提。', '王麻子', 0, 'f6a31f585ac849d1861f165582be7490', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416483+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 0, 'heading', 's001 | 王麻子回村 | 深夜，约莫子时三刻 | 王家村村口，老槐树下', NULL, 0, 'f827f576e25841f2aa561390c9df06d9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416483+00', NULL, NULL, NULL, NULL);
