INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 3, 'dialogue', '李秀英：有福……咱非得这时候回来？天亮了再进村不行吗？', '李秀英', 0, 'c00c2eb5515747ef8c2511dbadf80366', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'dialogue', '王麻子：等不到天亮。城里那些人……要是发现账本不见了，头一个就找这儿来。', '王麻子', 0, '591351fc2c344c81a5ffd9a5d630a705', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'dialogue', '李秀英：可村里人……他们要是问起这些年……', '李秀英', 0, '1240ea52125c4fb7a20e8b491e955b4e', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'dialogue', '王麻子：就说在省城做小买卖，赔了。记住，秀英，咱什么都不知道。账本的事，一个字都不能提。', '王麻子', 0, '638666b3f24745f4bebdf158c18f6061', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 7, 'dialogue', '王麻子：为了孩子。得让他生在干净地方。', '王麻子', 0, '9075630fcb5a475c84b6ad9c705eba88', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'action', '李秀英（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '595b9cca7b2a4a7b994473e4c566dbe0', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649045+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 6, 'dialogue', '王麻子：就说在省城做小买卖，赔了。记住，秀英，咱什么都不知道。账本的事，一个字都不能提。', '王麻子', 0, '7057dee0278d49b2995f530bbac45b55', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649046+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'action', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '960bc5b6783b418082630a1be37add14', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649046+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'action', '王麻子站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿。', NULL, 0, '9f1327644f7247b8ab63aa1cc8938e69', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649047+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'action', '李秀英靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, 'ab13711c55974abdb75757adb1d70d2c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649047+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'action', '王麻子蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, 'ce479560ff2640118a4edaccc8fe8088', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649048+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 4, 'dialogue', '王麻子：等不到天亮。城里那些人……要是发现账本不见了，头一个就找这儿来。', '王麻子', 0, 'd0ea2362c3e14822952c1eac61fd4634', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.649049+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, 'narration', '村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。', NULL, 0, 'df436b9590ef46b7888eb2c99b08bbb8', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.64905+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'action', '王麻子（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, 'f04d556b7849448f98f4a372f351beef', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:18.702421+00', '2026-03-01 12:16:21.64905+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 5, 'dialogue', '李秀英：可村里人……他们要是问起这些年……', '李秀英', 0, '35b3d13bd36049b1bf4ad7d8e74236fe', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416478+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'action', '李秀英（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '18ea228d2e414f03929a44a5f26b790f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416474+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'action', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, '25ba9915568f4540b2ea04503532f48e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416477+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'action', '就在这时，远处传来狗吠。不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影。', NULL, 0, '6a49a917578b4927bd0e3e4ef0770204', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416479+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'action', '王麻子蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, '6d3eef9b1f6d45e6a60d811d1652d28a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416479+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'action', '王麻子的脚步在槐树下骤然停住。他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, '75914e3dd53543cebbed0c4861b813c3', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.41648+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'action', '王麻子站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿。', NULL, 0, '90ffdd56b94e4473ad12ea3d0077579f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416481+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'action', '李秀英靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, 'ccad870c72b64797b86012d0b70338a4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:21.643521+00', '2026-03-01 12:16:22.416482+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 8, 'action', '王麻子（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。', NULL, 0, 'b6c9ef2dec5249c3bbb2a808b9e59840', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 9, 'action', '李秀英（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。', NULL, 0, '235692eb58dd433689eacae6ebc67aa1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 10, 'action', '王麻子的脚步在槐树下骤然停住。他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。', NULL, 0, 'e350357ad7d341218efa4cbc76a23202', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 11, 'action', '李秀英靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。', NULL, 0, 'a5813feef9304ce7be95a02dfc70846b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 12, 'action', '王麻子蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。', NULL, 0, 'cebc40699ae944d59eab353e65a50013', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 13, 'action', '王麻子站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿。', NULL, 0, 'ad7f5f9543c2420f889474658bc55bd3', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 14, 'action', '李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。', NULL, 0, 'e0ce2a62a28d4346a9422d11cd9b1b0f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);
INSERT INTO public.script_blocks (translation_project_id, chapter_id, seq_no, block_type, source_text, speaker_tag, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d7025af9b3764cb4a769be8250b0bf1d', 'chapter_904bae811e7e4e2c9a124bdb12f65be6', 15, 'action', '就在这时，远处传来狗吠。不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影。', NULL, 0, '629a4c3075f940dfa169e4d6363d6629', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:16:22.412261+00', '2026-03-01 12:16:22.412261+00', NULL, NULL, NULL, NULL);


