INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('de2e24c6e5774a1db6dcbde2317df9f7', 'b862f0a472084a77beab20538052ac2e', '“No one’s following,” he said in a low voice, more to convince himself. His voice was hoarse, parched from the long journey.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '0441e699eba34d148c0195753945f9e1', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356331+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('1c53a5edf0514659b8eddd123c8b0444', 'b862f0a472084a77beab20538052ac2e', 'In his left hand, he carried a bulging blue cloth bundle; his right hand gripped the wrist of the woman beside him.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '2691e819d2f64123999a261b9daf645d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356332+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('945ca29efb5d4550bcbc5ecda2167113', 'b862f0a472084a77beab20538052ac2e', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '4581d5a1cb8a48c0b5f159cfc90096ee', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356335+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b2fc325719e849a28a92206c2b2598f1', 'b862f0a472084a77beab20538052ac2e', 'Li Xiuying leaned against the locust tree’s rough trunk, panting, her chest rising and falling. She raised a hand to wipe her face—whether it was rain or tears, she couldn’t tell.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '6f2f1e7442e845c8a412ff47120c448b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356338+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c5edb1c5bf5c4a3d9c1bb24ef23be73d', 'b862f0a472084a77beab20538052ac2e', 'Li Xiuying (Wang Mazi’s wife) stumbled along, dragged by his pull. She was seven or eight years younger than Wang Mazi, her face delicate yet worn, the fine wrinkles at the corners of her eyes especially pronounced in the shadows. She was wrapped in a somewhat worn floral-patterned cotton-padded jacket, her hair hastily pinned up with a wooden hairpin, a few stray strands stuck to her temples with sweat. From time to time, she glanced back, her lips pressed pale, her other hand unconsciously protecting her lower abdomen—where a slight bulge showed, roughly four or five months into pregnancy.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '80f8f209d9c841679c8ca44622f15c53', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356339+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('5eb971d3b3e64aa9995e72dfe71c7e1d', 'b862f0a472084a77beab20538052ac2e', '### 【Action and Emotional Details】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '8bddaa70e05349779ff72890febf960d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.35634+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('cd7aaf6ececc49aabf73c4b8c213c25b', 'b862f0a472084a77beab20538052ac2e', 'Wang Mazi did not answer immediately. He crouched down, rummaged in the bundle, and pulled out an oil-paper package containing half a stiff, hard pancake. He broke off a small piece and handed it to his wife, then gnawed on an even smaller piece himself, chewing slowly, his eyes never leaving the road leading into the village.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'abdae369f31f4b72bae03929276b2950', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356341+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('f2ec3d9dce714e43960dd8afc483a6e8', 'b862f0a472084a77beab20538052ac2e', 'He released his wife’s wrist and turned to look back the way they had come. The dirt road stretched empty into the distance, only the wind moaning. Yet he squinted for a long while, his Adam’s apple bobbing up and down as if confirming something. Sweat trickled down his temples, leaving a damp trail across his cheekbones.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'bc4ac6cd90c74463b67687458fbe36ae', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356342+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e5d9611db04c42bda29d44793d46605e', '844b6f92a6874930b7e7a09e2f68d350', '# Wang Mazi Returns to the Village', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '22c56650036b4c88b9383b40a12c813c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974035+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d71be842f5eb42129a516d66d69461c4', 'b862f0a472084a77beab20538052ac2e', 'Wang Mazi didn''t answer immediately. He crouched down, rummaged in the bundle, and pulled out an oil-paper package containing half a piece of rock-hard flatbread. He broke off a small piece and handed it to his wife, then gnawed on an even smaller piece himself, chewing slowly, his eyes never leaving the road leading into the village.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'aa62041424024fd2947f738db0a49d76', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b4fc767e8c3445c894e3b09eacdf8336', '2312e0a93a6b4c8da66e19f864632e1b', '# 王麻子、村に帰る', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'febb30a591264d7fa31e4acdb65ec986', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('f1d540ee25404e61becd52719e393004', '2312e0a93a6b4c8da66e19f864632e1b', '## シーン一：村の入り口の老いたエンジュの木', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '3edee46a25db4f5fa1d9d3ab356313f1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('60ca4b20a2bc47909531162bf9cda64b', '2312e0a93a6b4c8da66e19f864632e1b', '**時間**：深夜、およそ子の刻三つ時  
**場所**：王家村村口，老槐树下  
**天気**：北風が唸り、黒雲が月を覆い、時折ぱらぱらと雨粒が落ちる', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '06c2587c4182475dab230092bc3f80b2', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
