INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('834e3b5a05dc4b74a3089b7cd26f0158', '2312e0a93a6b4c8da66e19f864632e1b', '村の入り口にある百年を経た老いたエンジュの木が、夜風の中で牙を剥き爪を立てるように揺れ、枯れ枝が幽鬼の爪のように揺らめき、砕けた揺らめく影を落としていた。幹に貼られた色あせた春聯の切れ端が風に吹かれてさらさらと音を立て、まるで誰かが低く囁いているようだった。村へと続く土の道は凸凹がひどく、水たまりには星の光ひとつ映らず、遠くにちらほらと見える数軒の家の窓枠から漏れる、ぼんやりとした油燈の灯りだけが、墨を流したような闇の中で震えていた。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '79707ab6e52a4b50a5ea1777a6d8a2f1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('7cff9fad02a0460389befe8e2749f16b', '2312e0a93a6b4c8da66e19f864632e1b', '北風が砂埃と枯れ葉を巻き上げて渦を巻き、空気には湿った土の匂いと、遠くの家畜小屋から漂うかすかな生臭さが漂っていた。さらに遠く、真っ黒な山々の輪郭が巨大な獣のようにうずくまり、このまもなく静けさを破られる村を黙って見下ろしていた。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'bec971e4dcd447f78a178aa04c6228ca', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
