INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('4e68552988d6479c8bdb987f81f72e06', 'b862f0a472084a77beab20538052ac2e', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '02aa3d92f2154078841b7e302e07eb45', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356327+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('fde8830436454284a835b741598bd765', 'b862f0a472084a77beab20538052ac2e', '"Just say we tried running a small business in the provincial capital and lost everything." Wang Mazi cut her off, his tone resolute. He stood up, slapping the dirt from his trouser legs, his movements carrying a fierce determination. "Remember, Xiuying, we know nothing. Not a single word about the ledger."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '32dac65f59e0419aa80d32392f80c574', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356333+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('6df91f90144f4a1caa7f2e23576086fa', 'b862f0a472084a77beab20538052ac2e', '"We can''t wait till dawn." He finally spoke, crumbs falling from the corner of his mouth. "Those people in the city... if they find the ledger is missing, this is the first place they''ll come looking."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '21ee490c70d34115abde07a8b41a9f89', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('441b8a1d23a14dddad19218e7ee9d666', 'b862f0a472084a77beab20538052ac2e', '"But the villagers..." Molly took the flatbread but didn''t eat it, her fingers unconsciously pinching its edge. "What if they ask about all these years..."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'a2e4d8f8e9d0472a92784f483f114196', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('69ce5804899c4b4d8e75d623c65b201d', 'b862f0a472084a77beab20538052ac2e', '"Just say we ran a small business in the provincial capital and lost it all." Wang Mazi cut her off, his tone decisive. He stood up, patted the dirt off his trouser legs, his movements carrying a fierce determination. "Remember, Xiuying, we know nothing. Not a single word about the ledger."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '55f3b9a25c774fcabdc689f29cae77cb', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('4a112d00ec30458f8447a60e63189f62', 'b862f0a472084a77beab20538052ac2e', 'Molly lowered her head, her fingers moving to her lower abdomen, gently stroking it. Wang Mazi saw this gesture; his eyes softened for an instant, but then hardened again.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '9fd9a75479f84883a14793f6e403bf49', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ca25221ee5504ef78e2667bb22615a18', 'b862f0a472084a77beab20538052ac2e', '"For the child." He added in a lowered voice. "He must be born in a clean place."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'e2152431a9a043298088ba84358c26c2', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('66a7acb7783d4fd0a2d434200e9cdb08', 'b862f0a472084a77beab20538052ac2e', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'dbf1cd9aa29c46788051a9deda5760bd', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('a48cfd1dc46744f489080aaff6dfa944', 'b862f0a472084a77beab20538052ac2e', '### 【Conflict Foreshadowing】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '92be3456121045c9b0d24b068e1cae04', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b1f2e49c28a04170a03f55fc9b7336b3', 'b862f0a472084a77beab20538052ac2e', 'At that moment, the sound of barking dogs came from the distance.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c576e9a690ed4a2b935d1168b860afd4', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0d67fca4ece54edc8f7c09619b3a8aac', 'b862f0a472084a77beab20538052ac2e', 'Not from one house, but one after another, starting from the east end of the village and rolling closer, spreading through the night like ripples. Wang Mazi stiffened all over, abruptly pulling his wife into the shadow of the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '379dc3d3d48d407486e57a9456058bc3', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('fff87b65c1434159a85a15b8012a1c56', 'b862f0a472084a77beab20538052ac2e', 'The north wind whirls sand, soil, and dead leaves in eddies. The air is thick with the damp smell of earth and a faint, distant odor of animal pens. Further away, the dark, indistinct outlines of the mountains crouch like giant beasts, silently watching over this village whose tranquility is about to be shattered.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '2cab0ef0e52840f59131d4b8335d8984', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:38.706257+00', '2026-03-01 08:59:01.441726+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('71b65ef195bd45abb5d951a161815746', 'b862f0a472084a77beab20538052ac2e', '## Scene One: The Old Locust Tree at the Village Entrance', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '3e611b0ec018421db92f860c2a578035', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:38.706257+00', '2026-03-01 08:59:01.441726+00', NULL, NULL, NULL, NULL);
