INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('883821eb65894fdbb2e1a6ae1f5c58d7', 'b862f0a472084a77beab20538052ac2e', '**Time**: Late at night, around the third watch (approximately 11:45 PM)  
**Location**: The entrance of Wang Family Village, under the old locust tree  
**Weather**: A north wind howls, dark clouds obscure the moon, with occasional scattered raindrops falling', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '9c918d13d7634cb7b3199d594f2eb84f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:38.706257+00', '2026-03-01 08:59:01.441733+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d3eb88a141c94903ba06cdab37c4f950', 'b862f0a472084a77beab20538052ac2e', '# Wang Mazi Returns to the Village', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'a71d0a1f5e394a2bbba5a186e1d0616f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:38.706257+00', '2026-03-01 08:59:01.441733+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0514ba3f668040e1918ac2b24438842a', 'b862f0a472084a77beab20538052ac2e', 'The century-old locust tree at the village entrance claws wildly in the night wind, its withered branches swaying like ghostly hands, casting fragmented, flickering shadows. Faded remnants of Spring Festival couplets pasted on the trunk rustle loudly in the wind, like someone whispering in a low voice. The dirt road leading into the village is pitted and uneven; puddles reflect not a single glimmer of starlight. Only the faint, yellowish glow of oil lamps seeps through the window lattices of a few scattered households in the distance, trembling within the ink-black night.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'af27faab1fd84c4aa43207d038f8d945', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:38.706257+00', '2026-03-01 08:59:01.441734+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('07b85c7cd3024945babf07b05b9c8a82', 'b862f0a472084a77beab20538052ac2e', '**Wang Mazi** (given name Wang Youfu) approaches from the far end of the dirt road, his footsteps heavy and hurried. He appears to be in his early forties, tall and lean with a slightly stooped back. He wears a faded navy-blue cotton-padded jacket, its cuffs frayed. The pockmarks on his face are barely discernible in the dim light, but his eyes are unusually bright—the kind of gaze belonging to someone long accustomed to traveling and worldly affairs. Yet now, they are mixed with weariness, anxiety, and a trace of barely perceptible wariness.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'e4feaa35672b4985afd77a9b4a14deac', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:38.706257+00', '2026-03-01 08:59:01.441734+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('42ac0af6133541478937676f98562a73', 'b862f0a472084a77beab20538052ac2e', '### 【Environmental Description】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'ee9f5948a6de4a08b838c5e292fa7649', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:38.706257+00', '2026-03-01 08:59:01.441735+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('89623f8ce5c94d68b32d1304610cbc70', 'b862f0a472084a77beab20538052ac2e', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'f69a09854645438b88ebb8ce07b4d8b4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:38.706257+00', '2026-03-01 08:59:01.441736+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('717578e5b57a4851b6ad5a7c58c6efee', 'b862f0a472084a77beab20538052ac2e', 'Li Xiuying lowered her head, her fingers moving to her lower abdomen, gently stroking it. Wang Mazi saw this gesture; his gaze softened for an instant, then hardened again.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '3ef871182df2488bb8341a73021d73fd', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356334+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('7a1f9815832a46ca94010ce182a05ee3', 'b862f0a472084a77beab20538052ac2e', '"We can''t wait till dawn." He finally spoke, crumbs falling from the corner of his mouth. "Those people in the city... if they find the ledger is missing, this is the first place they''ll come looking."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '519be17b65504037994074a038a9c33e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356335+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ab28d4139ca4456bbd2ad6679193f882', 'b862f0a472084a77beab20538052ac2e', '"For the child." He added in a lowered voice. "He must be born in a clean place."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '72a49efb2f934ebe8935cb7b1e9d9fb7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356338+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('a93b5d8a076f41848c1a6ec51623a468', 'b862f0a472084a77beab20538052ac2e', '### 【Foreshadowing Conflict】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '882f04d3971b4474ac15f0bb6db8fe15', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356339+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('6ea31b2e3b614c07b63127f5e0df0300', 'b862f0a472084a77beab20538052ac2e', '"But the villagers..." Li Xiuying took the flatbread but didn''t eat it, her fingers unconsciously pinching its edge. "What if they ask about all these years..."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c30a040a63fc400e920326b33997fafa', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356342+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ce74ce6180a64c40b92fafa0bab16fcf', 'b862f0a472084a77beab20538052ac2e', 'At that moment, the distant sound of barking dogs reached them.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'd09260e559594f7d97ec8e60b9e1fb9c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356343+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('110dc566d850476f99f6a37ed8163e05', 'b862f0a472084a77beab20538052ac2e', 'Not from one house, but one after another, starting from the east end of the village and rippling through the night. Wang Mazi stiffened, abruptly pulling his wife into the shadow of the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'dd7b8f6ae46a4690a6d8e237f5bc91be', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356344+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('228a2ac77fbe42bcb5be8e310a83055c', 'b862f0a472084a77beab20538052ac2e', '“Youfu…” her voice trembled, “must we come back now? Couldn’t we wait till daybreak to enter the village?”', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'deeea88190d54c098695ffa918254c64', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356344+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('95fbab4eedeb415986c5b04de4e86f99', 'b862f0a472084a77beab20538052ac2e', '', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'e247fc64cb3c4153aa30c75e1b24e0ec', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356346+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ee11b600488d470cb27536ef1c651a37', 'b862f0a472084a77beab20538052ac2e', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'fe93a2b0b7be4be2b9750c9c2887855c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356346+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('1e7ad710fd3c42648cdda01dfb673803', '2312e0a93a6b4c8da66e19f864632e1b', '**王麻子**（本名王麻子（本名王有福））が土の道の果てから歩いてくる。足取りは重く、かつ急である。彼は四十前後、背は高く痩せていて、背中は少し丸まり、洗いざらして白っぽくなった藍色の綿入れを着ており、袖口は擦り切れて毛羽立っていた。顔のあばたは薄暗い光ではっきりとは見えないが、その目は異常に鋭く光っていた――それは長年外を駆け回り、世間を見てきた者だけが持つ眼差しで、今は疲労と焦燥、そしてかすかに見え隠れする警戒心が混ざり合っていた。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c3cf30a386e246b5a53a5918c6f5966d', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('7ba9d568ac664476a6f0f9894a680de8', '2312e0a93a6b4c8da66e19f864632e1b', '「でも村の人たちは……」李秀英は餅を受け取ったが、食べずに、無意識に餅の端を指でつまんでいた。「もしあの人たちが、この何年かのことを聞いてきたら……」', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '5c558bb0384649d19f286bdd717ff63c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ea7ded8a69e641e789107ff531bd05f0', '2312e0a93a6b4c8da66e19f864632e1b', '「省都で小商いをして、失敗した、と言え。」王麻子は彼女の言葉を遮り、その口調は断固たるものだった。彼は立ち上がり、ズボンの裾についた土を払い落とした。その動作には、ある種の凄みが込められていた。「覚えておけ、秀英、俺たちは何も知らない。帳簿のことは、一言も口にするな。」', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '1e9120d47e0f42afabc240cf2fa79521', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('af868a445ae14baa955fdd1d822dee64', '2312e0a93a6b4c8da66e19f864632e1b', '李秀英はうつむき、指をお腹に当てて、そっと撫でた。この仕草を王麻子は目に留め、一瞬、彼の目つきは和らいだが、すぐにまた硬直した。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'acd7ce3e574b4469932380b7e9723b04', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('7566be3045424a1a93bc582bbb1942aa', '2312e0a93a6b4c8da66e19f864632e1b', '「子供のためだ。」彼は声を潜めて、付け加えた。「あいつをきれいな場所で産ませてやらなきゃ。」', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c9f9cc45777b4f789aa77b96c8e48efb', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('fd373bbe628749349fc05b2cc03994ce', '2312e0a93a6b4c8da66e19f864632e1b', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '5b0a037829be491abb4c19e221b4c202', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9b47bdb6049541ccab634f83777b8407', '2312e0a93a6b4c8da66e19f864632e1b', '### 【衝突への伏線】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'ae8c06a828c14369a8dadf987a660de8', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('5c024afad5de403f95fdd5b1b05ab7af', '2312e0a93a6b4c8da66e19f864632e1b', 'ちょうどその時、遠くから犬の吠える声が聞こえてきた。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '12bc59349a8d44a8a6318093c2062b7f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('f7fbe563574944e2a2bb136b79b5d4ff', '2312e0a93a6b4c8da66e19f864632e1b', '一匹ではなく、次から次へと、村の東端からこちらへと響き渡り、夜闇の中で波紋のように広がっていく。王麻子は全身を硬直させ、妻をエンジュの木陰にぐいっと引き寄せた。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '86e764ff60564c1f8511d2d06fc59cde', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d37728690f5f4590a5b0faed338592f4', '844b6f92a6874930b7e7a09e2f68d350', 'Not from one house, but rising and falling in succession, echoing from the east end of the village and spreading through the night like ripples. Wang Mazi stiffened all over, abruptly pulling his wife into the shadow of the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '036fc2e75f614669b4300c9fbe547b8a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974026+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('95ad879317014b89a4aa19e011aafc90', '844b6f92a6874930b7e7a09e2f68d350', '"Just say we ran a small business in the provincial capital and lost it all." Wang Mazi cut her off, his tone resolute. He stood up, slapping the dirt off his trouser legs, his movements carrying a fierce determination. "Remember, Xiuying, we know nothing. Not a single word about the ledger."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '0cd00013542f41b985b6ddfdeda2c134', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.97403+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('6dd8e7e2c48d402ea336466bbc4f5e8b', '844b6f92a6874930b7e7a09e2f68d350', '**Li Xiuying** (Wang Mazi''s wife) stumbled along, dragged by him. She was seven or eight years younger than Wang Mazi, with delicate yet haggard features; the fine wrinkles at the corners of her eyes were especially pronounced in the shadows. She was wrapped in a somewhat worn, floral-patterned cotton-padded jacket, her hair hastily pinned up with a wooden hairpin, a few stray strands stuck to her temples with sweat. She kept glancing back, her lips pressed together until they were pale, her other hand unconsciously protecting her lower abdomen—which was slightly rounded, suggesting a pregnancy of about four or five months.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '108573fcffa240faa31085a53be6570a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974031+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0c46abd4957d43e984be72dfdc1b777b', '844b6f92a6874930b7e7a09e2f68d350', '"No one''s following," he said in a low voice, more to convince himself. His voice was hoarse, parched from the long journey.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '121c9b93b22a4ce4add29c612065a151', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974032+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('bae65b8afe5247339042f3057bec03c0', '844b6f92a6874930b7e7a09e2f68d350', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '1248e10e9cb9495eb21012bde1e48f44', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974032+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('54ec600d91ab458b9b442c5b1eba185d', '844b6f92a6874930b7e7a09e2f68d350', 'At that moment, the distant sound of barking dogs came.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '1293e721223d42f892fff55dca058310', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974033+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c04e2751c6f34164af3c81538320354a', '844b6f92a6874930b7e7a09e2f68d350', '"Youfu…" her voice trembled, "Do we have to come back now? Couldn''t we wait until daybreak to enter the village?"', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '16909ff9cb1e4230aeaf408380a9810b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974033+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('bde06c88a1a54d43b37447674b437106', '844b6f92a6874930b7e7a09e2f68d350', '**Li Xiuying** leaned against the locust tree''s rough trunk, panting, her chest heaving. She raised a hand to wipe her face, unsure whether it was rain or tears.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '18ce294d257f4a05a9a8adab7aba43d6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974034+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('80047440eb6c4eb295baa89d7f27656c', '844b6f92a6874930b7e7a09e2f68d350', 'The century-old locust tree at the village entrance claws wildly in the night wind, its withered branches swaying like ghostly hands, casting fragmented, flickering shadows. Faded remnants of spring couplets pasted on the tree trunk rustle loudly in the wind, like someone whispering in a low voice. The dirt road leading into the village is pitted and uneven; puddles reflect not a single glimmer of starlight. Only the faint, yellowish glow of oil lamps seeps through the window lattices of a few scattered households in the distance, trembling in the ink-black night.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '1c6467fd1ae2404f90399859ca4f31c7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974034+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d00cc9b78daf455b876d1b133777f47b', '844b6f92a6874930b7e7a09e2f68d350', '**Wang Mazi''s** footsteps came to an abrupt halt beneath the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '2bb6d5c85b184cf199d02a631335d0af', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974035+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('bfa0902bed3642ec95e9e18b0d837070', '844b6f92a6874930b7e7a09e2f68d350', 'Wang Mazi did not answer immediately. He crouched down, rummaged in the bundle, and pulled out an oil-paper package containing half a stiff, hard pancake. He broke off a small piece and handed it to his wife, then gnawed on an even smaller piece himself, chewing slowly, his eyes never leaving the road leading into the village.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '4726ffd3954e45e6805c34422a21352c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974035+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('31109c63ad02479ea7c7af48bece7d3a', '844b6f92a6874930b7e7a09e2f68d350', '### 【Action and Emotional Details】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '4ca1d3881f78452997bbaeaeae67b47c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974036+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d6cab806a4a546d6883566ab85fd10a5', '844b6f92a6874930b7e7a09e2f68d350', '"We can''t wait till dawn." He finally spoke, crumbs falling from the corner of his mouth. "Those people in the city... if they find the ledger is missing, this is the first place they''ll come looking."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '4d0c01afbb6c4d589a00ff74088e78ac', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974036+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('fc24b82450264c0b83cb952793b71e80', '844b6f92a6874930b7e7a09e2f68d350', '### 【Foreshadowing Conflict】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '4f21a1a288294c9988d36b68fdf95e78', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974037+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('409797151f984ea79ffcdc23642c76bf', '844b6f92a6874930b7e7a09e2f68d350', '**Time**: Late at night, around the third watch (approximately 11:45 PM)  
**Location**: The entrance of Wang Family Village, under the old locust tree  
**Weather**: The north wind howls, dark clouds obscure the moon, with occasional scattered raindrops falling.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '657a567d97ca4d32a19ea6b7275e8466', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974037+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('98f5b1445ff049a18468d59fc778108d', '844b6f92a6874930b7e7a09e2f68d350', 'The north wind whirls sand, soil, and dead leaves into eddies. The air is thick with the damp smell of earth and a faint, distant odor of animal pens. Further away, the dark, indistinct outlines of the mountains crouch like giant beasts, silently watching over this village whose tranquility is about to be shattered.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '6795aa2b30ba4fa6b573060d1eb3d509', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974038+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('3809ef0c1f53414e84bbbea053d113ba', '844b6f92a6874930b7e7a09e2f68d350', '"For the child." He added in a lowered voice. "He must be born in a clean place."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '6cf152ce341f4b5da02f26ea99da587f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974038+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('76d168960b574eb4a23f0b58cbcf6dec', '844b6f92a6874930b7e7a09e2f68d350', 'In his left hand, he carried a bulging blue cloth bundle; his right hand gripped the wrist of the woman beside him.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '742d8389025c442d8dc679ccd267a6bd', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974039+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('af938a459f6448a7a6b36bf1527b6e46', '844b6f92a6874930b7e7a09e2f68d350', 'He released his wife''s wrist and turned to look back the way they had come. The dirt road stretched empty into the distance, with only the wind''s mournful howl. Yet he still squinted, peering for a long while, his Adam''s apple bobbing up and down as if confirming something. Sweat trickled down his temples, leaving a damp trail on his cheekbones.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '836c1005f0fa48fab39a0ed6e49fb176', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974039+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('24bdc52dccc0430290a024400192802a', '844b6f92a6874930b7e7a09e2f68d350', '## Scene One: The Old Locust Tree at the Village Entrance', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '9c66cf9ddd8544468d6fb7a473accd8e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.97404+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('95e37cc86cdb408f922901688c03b75c', '844b6f92a6874930b7e7a09e2f68d350', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'aaa63c9883cb4f438bdbef8587c8f282', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.97404+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c1e6da9ff0b346d49bd35e1874c610b0', '844b6f92a6874930b7e7a09e2f68d350', '**Wang Mazi** (given name Wang Youfu) approaches from the far end of the dirt road, his footsteps heavy and hurried. He appears to be in his early forties, tall and lean with a slightly stooped back. He wears a faded navy-blue cotton-padded jacket, its cuffs frayed. The pockmarks on his face are barely discernible in the dim light, but his eyes are unusually bright—the kind of gaze belonging to someone long accustomed to life on the road, seasoned by the world. At this moment, however, they are mixed with weariness, anxiety, and a trace of barely perceptible wariness.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'b948f5c178d3492f851629a2aaaa7ea1', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974041+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2387e0efff0f4772ab74530994c8a543', '844b6f92a6874930b7e7a09e2f68d350', 'Li Xiuying lowered her head, her fingers moving to her lower abdomen, gently stroking it. Wang Mazi saw this gesture; his gaze softened for an instant, then hardened again.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'bbbfe128dc9649e6894254a74a8be5de', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974041+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b6b6cd45dcb841a29b49fb8731e57f12', '844b6f92a6874930b7e7a09e2f68d350', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c320df7817d2450b9f6260a4be2008ba', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974041+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('af5a2047d4ba4f9a9e0f928423b205a5', '844b6f92a6874930b7e7a09e2f68d350', '"But the villagers..." Li Xiuying took the flatbread but didn''t eat it, her fingers unconsciously pinching its edge. "What if they ask about all these years..."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c59c75056e2345ec80d78673570f0ed7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:19:56.941819+00', '2026-03-01 06:18:55.892343+00', '2026-03-01 08:19:56.974042+00', NULL, NULL, NULL, NULL);
