INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9a20176c2ed04c27a63cd63a05b8d2df', '844b6f92a6874930b7e7a09e2f68d350', '## Scene One: The Old Locust Tree at the Village Entrance', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'd9a1ab089a284a38884ed7c8410bc96b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('f2e863ace0144b0eaee6d42f9b262efc', '844b6f92a6874930b7e7a09e2f68d350', '**Time**: Late at night, around the third watch (approximately 11:45 PM)  
**Location**: Wang Family Village entrance, beneath the old locust tree  
**Weather**: A north wind howls, dark clouds obscure the moon, occasional scattered raindrops fall', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '30a7c37cdb324427a07ec7f22be67732', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('8ad72c6aa0024741a9230fca6dd4f434', '844b6f92a6874930b7e7a09e2f68d350', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'd4480a8efff54755990e1122b2c093cc', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c836e8ff7d2741519da680a14b7e7857', '844b6f92a6874930b7e7a09e2f68d350', '### 【Environmental Description】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '9c7611db23334ae5b23caec1fa1f472b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('5c10bed6f3e64d0e9fbd64e6bb5d3bf6', '844b6f92a6874930b7e7a09e2f68d350', 'The century-old locust tree at the village entrance claws wildly in the night wind, its withered branches swaying like ghostly hands, casting fragmented, quivering shadows. Faded remnants of Spring Festival couplets pasted on the trunk rustle loudly in the wind, like someone whispering in a low voice. The dirt road leading into the village is pitted and uneven; puddles reflect not a single glimmer of starlight. Only the faint, trembling halos of dim oil lamps shine through the window lattices of a few scattered households in the distance, quivering in the ink-black night.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'd621c50cad884c60b89f2ec908886275', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('4bec7e5c8db841388bde33573a46e29c', '844b6f92a6874930b7e7a09e2f68d350', 'The north wind whirls sand and dead leaves; the air is thick with the damp smell of earth and a faint, distant odor of animal pens. Further away, the dark, hulking outlines of the mountains crouch like great beasts, silently watching over this village whose peace is about to be shattered.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '27f8192bdb4f4d52b8aee9f9aafb3fb6', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('528d78d7775a4a0b9f163c58ce6f25c9', '844b6f92a6874930b7e7a09e2f68d350', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '917c08db2e50479f80f6c670e85231b2', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('1b81c3989f90431a9c25a27111a02061', '844b6f92a6874930b7e7a09e2f68d350', '### 【Character Entrance】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'd7d095f0ec8c4936932e1aea00e0fd45', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('4d9412d1ca1c41c088dd6907d7f451b0', '844b6f92a6874930b7e7a09e2f68d350', '**Wang Mazi** (given name Wang Youfu) approaches from the end of the dirt road, his footsteps heavy and hurried. He appears to be in his early forties, tall and lean with a slightly stooped back, wearing a faded navy-blue cotton jacket with frayed cuffs. In the dim light, the pockmarks on his face are hard to make out clearly, but his eyes are unusually bright—the kind of gaze belonging to someone long accustomed to traveling and worldly affairs, yet now mixed with weariness, anxiety, and a trace of barely perceptible wariness.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '8c17bd917cb24e30b7b197285ef8805b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('769f74def4024f9c9c80e969caea25d8', '844b6f92a6874930b7e7a09e2f68d350', 'In his left hand, he carried a bulging blue cloth bundle; his right hand gripped the wrist of the woman beside him.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '4569d35e291149b8989663e1fe013755', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('8260552e0d3f4b2e8c53b15bb77ab2de', 'b862f0a472084a77beab20538052ac2e', '"Youfu…" her voice trembled, "must we come back now? Couldn''t we wait until daybreak to enter the village?"', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '52338f1609064fc8b421b8e6740aa862', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:38.706257+00', '2026-03-01 08:59:01.441728+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('67d73af07cde421bbf6b76e5cc323287', '844b6f92a6874930b7e7a09e2f68d350', '**Li Xiuying** (Wang Mazi''s wife) stumbled along, dragged by him. She was seven or eight years younger than Wang Mazi, with delicate yet haggard features; the fine wrinkles at the corners of her eyes were especially pronounced in the shadows. She was wrapped in a somewhat worn, floral-patterned cotton-padded jacket, her hair hastily pinned up with a wooden hairpin, a few stray strands stuck to her temples with sweat. She kept glancing back, her lips pressed together until they were pale, her other hand unconsciously protecting her lower abdomen—which was slightly rounded, suggesting a pregnancy of about four or five months.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '0c000ae3f2a5404baa94ba29b16727b9', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b844577a2f1e4caa90fc81023da4db4d', '844b6f92a6874930b7e7a09e2f68d350', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '17bbb7ee97e34ebfa2c84895cc24110c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('37d3e560d7ca4b1f821c3652ffdb1e20', '844b6f92a6874930b7e7a09e2f68d350', '### 【Action and Emotional Details】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '0b8b721dceb0481ca0d82094236ca7c0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0cefe182e2944503bb7d0e370102072f', '844b6f92a6874930b7e7a09e2f68d350', '**Wang Mazi''s** footsteps came to an abrupt halt beneath the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '04aef7223cf14f78aaf0b0365505f19d', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('fdbd11389ceb442b9f4a415640363c64', '844b6f92a6874930b7e7a09e2f68d350', 'He released his wife''s wrist and turned to look back the way they had come. The dirt road stretched empty into the distance, with only the wind''s mournful howl. Yet he squinted and stared for a long time, his Adam''s apple bobbing up and down as if confirming something. Sweat trickled down his temples, leaving a damp trail on his cheekbones.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'b0191931f92044bd85bedb4d1661cc63', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('f92eee62f63e419db4dbe23f8f17146f', '844b6f92a6874930b7e7a09e2f68d350', '"No one''s following," he said in a low voice, more to convince himself. His voice was hoarse, parched from the long journey.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '8725b8b091f043cf9aaeede9770f8b55', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('60228dda4e3c468796615da113635f1f', '844b6f92a6874930b7e7a09e2f68d350', '**Li Xiuying** leaned against the locust tree''s rough trunk, panting, her chest heaving. She raised a hand to wipe her face, unsure if it was rain or tears.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '9fe371074f6b4a7aa5f1ac4ef34cca3c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('eb97e809bbd64ffeb7059625fcb78fb1', '844b6f92a6874930b7e7a09e2f68d350', '"Youfu…" her voice trembled, "do we have to come back now? Couldn''t we wait until daybreak to enter the village?"', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c07150e6071c4a06be0e22fb16cf4f89', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0cb28528259e45dca51337d9a10d8fd1', '844b6f92a6874930b7e7a09e2f68d350', 'Wang Mazi did not answer immediately. He crouched down, rummaged in the bundle, and pulled out an oil-paper package containing half a stiff, hard pancake. He broke off a small piece and handed it to his wife, then gnawed on an even smaller piece himself, chewing slowly, his eyes never leaving the road leading into the village.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'e08d6aea72ee46e49f23f467b6e670aa', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('76016b170757458e8d9160cf99d9551b', '844b6f92a6874930b7e7a09e2f68d350', '"We can''t wait till dawn." He finally spoke, crumbs falling from the corner of his mouth. "Those people in the city... if they find the ledger is missing, this is the first place they''ll come looking."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '8442cc0c5e294e69a1325cd1bfc421e7', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9a5809ddce9145909ad5a94765c55448', '844b6f92a6874930b7e7a09e2f68d350', '"But the villagers..." Li Xiuying took the flatbread but didn''t eat it, her fingers unconsciously pinching its edge. "What if they ask about all these years..."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '17d67a745b704e5181eb8d28d5ab6a2c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('014b1bf4a73a4e7283706f3d3c8308e7', '844b6f92a6874930b7e7a09e2f68d350', '"Just say we ran a small business in the provincial capital and lost money." Wang Mazi cut her off, his tone resolute. He stood up, slapping the dirt off his trouser legs, his movements carrying a fierce determination. "Remember, Xiuying, we know nothing. Not a single word about the ledger."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '749b20df13b14bfeb9afed2c1d8120a5', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('3aa8ffd815d8403a87f3dad9a2daba2d', '844b6f92a6874930b7e7a09e2f68d350', 'Li Xiuying lowered her head, her fingers moving to her lower abdomen, gently stroking it. Wang Mazi saw this gesture; his eyes softened for an instant, then hardened again.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c230c1d7936f40deb5fded3ae9acd106', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
