INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('a09e2d15fdf3460e9f8cc06fbe2d6238', '844b6f92a6874930b7e7a09e2f68d350', 'Not from one house, but one after another, echoing from the east end of the village and spreading through the night like ripples. Wang Mazi stiffened all over, abruptly pulling his wife into the shadow of the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'aab280c5eef242b9aed08773364de2b9', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:20:00.270395+00', '2026-03-01 08:20:00.270395+00', NULL, NULL, NULL, NULL);
