INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0e2cb3655d4548b99a8474a25925efc7', 'b862f0a472084a77beab20538052ac2e', 'Wang Mazi''s footsteps came to an abrupt halt beneath the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'fb3defdfaa6c4de6b5a25fb27390e58a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:38.706257+00', '2026-03-01 08:59:01.441737+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b038a51e78de4d7887797f9c01f3a49d', 'b862f0a472084a77beab20538052ac2e', 'He released his wife''s wrist and turned to look back the way they had come. The dirt road stretched empty into the distance, with only the wind''s mournful howl. Yet he still squinted for a long while, his Adam''s apple bobbing up and down as if confirming something. Sweat trickled down his temples, leaving a damp streak across his cheekbones.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'ff8a8399150b40359611f8cc0dc80d9f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 08:59:01.407356+00', '2026-03-01 07:08:38.706257+00', '2026-03-01 08:59:01.441737+00', NULL, NULL, NULL, NULL);
