INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('5fa244514a9b41d08b073770b8c49c44', 'b862f0a472084a77beab20538052ac2e', '## Scene One: The Old Locust Tree at the Village Entrance', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '8c1812b5732949528b37a2416c262229', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:47.042288+00', '2026-03-01 09:44:15.646567+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('92c60773d9304fd2af77821e72c2e93f', 'b862f0a472084a77beab20538052ac2e', '**Wang Mazi** (given name Wang Youfu) approaches from the end of the dirt road, his footsteps heavy and hurried. He appears to be in his early forties, tall and lean with a slightly hunched back, wearing a faded navy-blue cotton jacket with frayed cuffs. In the dim light, the pockmarks on his face are hard to make out clearly, but his eyes are unusually bright—the kind of gaze belonging to someone long accustomed to traveling and worldly affairs, yet now mixed with weariness, anxiety, and a trace of barely perceptible wariness.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'a38414ad470b4271b84f7ef879656caa', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:47.042288+00', '2026-03-01 09:44:15.646568+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b26d1495254340168a0e8fa4c6c92dff', 'b862f0a472084a77beab20538052ac2e', 'The north wind whirls sand, soil, and dead leaves; the air is thick with the damp smell of earth and a faint, distant odor of animal pens. Further away, the dark, indistinct outlines of the mountains crouch like giant beasts, silently watching over this village whose peace is about to be shattered.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'f9f2742f1c1d438e8205affab85046ac', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:47.042288+00', '2026-03-01 09:44:15.646568+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('4b6e6b44e09f41a684249fba70f81ae8', 'b862f0a472084a77beab20538052ac2e', '### 【Character Entrance】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'fd5eb9ce6b374534808d5e04b2c1a5d7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:47.042288+00', '2026-03-01 09:44:15.646569+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('80704e5e24f64508831a4c1527ca547a', 'b862f0a472084a77beab20538052ac2e', 'The century-old locust tree at the village entrance claws wildly in the night wind, its withered branches swaying like ghostly hands, casting fragmented, flickering shadows. Faded remnants of spring couplets pasted on the tree trunk rustle loudly in the wind, like someone whispering in a low voice. The dirt road leading into the village is pitted and uneven; puddles reflect not a single glimmer of starlight. Only the faint, trembling halos of dim oil lamps shine through the window lattices of a few scattered households in the distance, quivering in the ink-black night.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'ffb8ff517ab9438896945c18387829bf', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:44:15.611576+00', '2026-03-01 09:28:47.042288+00', '2026-03-01 09:44:15.646569+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('a3e48492f90a47eab9819cfefef95234', 'b862f0a472084a77beab20538052ac2e', 'The century-old locust tree at the village entrance claws wildly in the night wind, its withered branches swaying like ghostly hands, casting fragmented, flickering shadows. Faded remnants of Spring Festival couplets pasted on the tree trunk rustle loudly in the wind, like someone whispering in a low voice. The dirt road leading into the village is pitted and uneven; puddles reflect not a single glimmer of starlight. Only the faint, yellowish glow of oil lamps seeps through the window lattices of a few scattered households in the distance, trembling in the ink-black night.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '0cfad0bd9b8943388262821cbc7a8d9e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952498+00', NULL, NULL, NULL, NULL);
