INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('392ffe3b32f34228ab64b9f53b3ec84a', '2312e0a93a6b4c8da66e19f864632e1b', '彼は左手に膨らんだ蓝布包袱を提げ、右手で傍らの女の手首をぎゅっと握りしめていた。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '5a69df288414470880f625fcb84b4b9d', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e4b7fe9352784ea180159a0982d96eb9', '2312e0a93a6b4c8da66e19f864632e1b', '**李秀英**（王麻子の妻）は彼に引っ張られてよろめいた。彼女は王麻子より七八歳若く、顔立ちは端麗だが憔悴しており、目尻の細かい皺が影の中でひときわ目立っていた。半ば古びた花柄の綿入れをまとい、髪は木の簪でぞんざいに結い上げられ、数筋の前髪が汗でこめかみに貼りついていた。彼女は折に触れて振り返り、唇を真っ白に結び、もう一方の手は無意識にお腹を守るようにしていた――そのあたりはわずかに膨らみ、およそ四五ヶ月の身重らしかった。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'f42314ae150b4ac298344e1a325fc08c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
