INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d32c48d846f942e48b16687628854cd9', '2312e0a93a6b4c8da66e19f864632e1b', '### 【動作と感情の細部】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'e373d629e89a437f8b950cafbabeb31b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d862091194fd4179be443bf53f5e6d51', '2312e0a93a6b4c8da66e19f864632e1b', '**王麻子**の足取りはエンジュの木の下で突然止まった。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'ce4767b00efc4d7d969fe9e3379f5a14', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('7782e0dd274a45d79621080fdd975570', 'b862f0a472084a77beab20538052ac2e', '# Wang Mazi Returns to the Village', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'b2de83f8d38c4297b61167b60181571f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('17b02b7a03be4ed68e4bad3de34c273c', 'b862f0a472084a77beab20538052ac2e', '## Scene One: The Old Locust Tree at the Village Entrance', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '8b15acc9384b41868baa6b829efc28e6', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('bd1230eabcd14339a838def6cea17695', 'b862f0a472084a77beab20538052ac2e', '**Time**: Late at night, around the third watch (approximately 11:45 PM)  
**Location**: Out by the county line oak  
**Weather**: A north wind howls, dark clouds blot out the moon, and occasional scattered raindrops fall.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '62edeecfca0e48cea2d099d73ce1d1eb', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('7dfd6d7dce344201868a8a93a2705afe', 'b862f0a472084a77beab20538052ac2e', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'fa73a8e659e6459b9ead140609902a7e', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b010329181394a0dac97454411b196c8', 'b862f0a472084a77beab20538052ac2e', '### 【Environmental Description】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'd2bed5b257934641bc1f7dd22bab572b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('96228aba3b1743cfaf417c2a5d162b06', 'b862f0a472084a77beab20538052ac2e', 'The century-old locust tree at the village entrance claws at the night wind, its withered branches swaying like ghostly hands, casting fragmented, flickering shadows. Faded remnants of New Year couplets pasted on the trunk rustle loudly in the wind, like someone whispering in a low voice. The dirt road leading into the village is pitted and uneven; puddles reflect not a single starlight. Only the faint, yellowish glow of oil lamps seeping through the window lattices of a few scattered households in the distance trembles within the ink-black night.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'e741280cce1d49c7b6c7125bcfe1f883', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2781e809cb024e8391d8ac6776448485', 'b862f0a472084a77beab20538052ac2e', 'The north wind whirls sand, dust, and dead leaves; the air is thick with the damp smell of earth and a faint, distant stench from the livestock pens. Further away, the dark, indistinct outlines of the mountain ranges crouch like giant beasts, silently watching over this village whose tranquility is about to be shattered.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '370e7bd39d1d43ac8f2bff5c18965f33', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e641f0a0ae854e47b3c0a7802aab44d9', 'b862f0a472084a77beab20538052ac2e', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '88bf2f993d614315bc3d5a74f1050fd0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c09eff4c392b4513977230b45a10c0e3', 'b862f0a472084a77beab20538052ac2e', '### 【Character Entrance】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '8b06ed2ea51342bc81c43c98ff5c28d7', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ce261a25e5564582a7bc886071e6a27f', 'b862f0a472084a77beab20538052ac2e', '**Wang Mazi** (real name Cletus) approaches from the end of the dirt road, his steps heavy and hurried. He appears to be in his early forties, tall and lean with a slightly hunched back, wearing a faded navy-blue cotton-padded jacket with frayed cuffs. The pockmarks on his face are barely discernible in the dim light, but his eyes are unusually bright—the kind possessed by someone long accustomed to traveling and worldly affairs. At this moment, however, they are mixed with weariness, anxiety, and a trace of barely perceptible wariness.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '623a533092694dd598d8d488b83eb492', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('58dc42bc21924610a484cc6dc06a4454', '2312e0a93a6b4c8da66e19f864632e1b', '彼は妻の手首を離し、振り返って来た方向を見つめた。土の道の先には誰もおらず、ただ風が泣くように吹いていた。それでも彼は長い間目を細めて見つめ、喉仏を上下させ、何かを確認しているようだった。汗が彼の鬢を伝って流れ、頬骨のあたりに湿った痕を残した。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '37c432687b2c47b5a6bbb34aa3cd7c0b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('303b6681b43c478288420d061eeb9234', '2312e0a93a6b4c8da66e19f864632e1b', '「誰もついてきてない」彼は低声で言った。それはむしろ自分自身を説得するかのようだった。声はかすれ、長旅の後の乾きを帯びていた。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'fb5ae9017b0640b8a20772d5dfec71cb', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9abff49263b84edda3dc7a15609c89b2', '2312e0a93a6b4c8da66e19f864632e1b', '**李秀英**はエンジュの木のごつごつした幹にもたれかかり、息を切らして胸を上下させた。彼女は手を上げて顔をぬぐった。それが雨か涙かはわからなかった。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '7972114c32364f568241f78c3ed4f673', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9becd09d873646b7a19bd13bce66b56f', '2312e0a93a6b4c8da66e19f864632e1b', '「有福……」彼女の声は震えていた。「どうして今、戻らなきゃいけないの？夜が明けてから村に入ればいいじゃない？」', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'f3f8e801369b40fb92a6948e8ad810a5', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('13bfbec26f4c4611b592246530d03a9d', '2312e0a93a6b4c8da66e19f864632e1b', '王麻子はすぐには答えなかった。彼はしゃがみ込み、包みから油紙包みを取り出した。中には半分の硬い焼き餅が入っていた。彼は小さく一口分を折って妻に渡し、自分はさらに小さいかけらをかじった。ゆっくりと噛みしめ、目は村の入り口への道から離さなかった。', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '2e105bbce99049558efe39adc7c4f203', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2378484f012548dcbe21ef4700f469e0', 'ada3637a24de44db91c1359958e586a5', '"We can''t wait till dawn." He finally spoke, crumbs falling from the corner of his mouth. "Those people in the city... if they find the ledger is missing, this is the first place they''ll come looking."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'd19419f604fa4799ab92500dd0390a1f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('639ee24af6284488a493531d3e83bd24', 'b99582ef92864d0dbc119d4ac347b087', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '1fd83704c87d4fff852a84553983a4b6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.60208+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b8bdbb990eb047ca89c753c7aca15a8b', 'b862f0a472084a77beab20538052ac2e', '', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '00c33de6173b41b1b1173aefc41244ee', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952494+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e24569c318ef43a6b44ad8eda4c7024b', 'b862f0a472084a77beab20538052ac2e', '"No one''s following," he said in a low voice, more to convince himself. His voice was hoarse, parched from the long journey.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '1275159df5714c2aa6ac2dc0c7d4bf63', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952499+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('f1ed51a8f52c4c269e15853babd98433', 'b862f0a472084a77beab20538052ac2e', 'At that very moment, the distant sound of barking dogs reached them.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '16b5e1a92b684a4bb82e2aa22b0bae9a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952499+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c9677edb07774f72ba46aabc6f8b0206', 'b862f0a472084a77beab20538052ac2e', '"We can''t wait till dawn." He finally spoke, crumbs falling from the corner of his mouth. "Those people in the city... if they find the ledger is missing, this is the first place they''ll come looking."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '17697efc9a1e469ca9599e9747d2a6be', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.9525+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('4088e8470ba747dbb2661023d249f9cb', 'b862f0a472084a77beab20538052ac2e', '### 【Action and Emotional Details】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '201fa13f96ce410bb3cb4a68f236c40a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.9525+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('3244b2b7cc194e448fe373ad0d8f6475', 'b862f0a472084a77beab20538052ac2e', '**Li Xiuying** leaned against the locust tree''s rough trunk, panting, her chest heaving. She raised a hand to wipe her face, unsure whether it was rain or tears.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '38aa9703848e43ca96e76183869ca480', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952501+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ccc2d7fd6b0b4d95b843a6dcd46b6aab', 'b862f0a472084a77beab20538052ac2e', 'He released his wife''s wrist and turned to look back the way they had come. The dirt road stretched empty into the distance, with only the wind''s mournful howl. Yet he still squinted and stared for a long time, his Adam''s apple bobbing up and down as if confirming something. Sweat trickled down his temples, leaving a damp trail on his cheekbones.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '3fa4be1178a346d69a599d3d96b8a4d0', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952501+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b098a5c686b14fa8b363524f894abdef', 'b862f0a472084a77beab20538052ac2e', 'Li Xiuying lowered her head, her fingers moving to her lower abdomen, gently stroking it. Wang Mazi saw this gesture; his eyes softened for an instant, then hardened again.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '433797055623413baab823f05d3402c6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952502+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('17e06ab4802b409882e5051a461f72b5', 'b862f0a472084a77beab20538052ac2e', 'Not from one house, but one after another, starting from the east end of the village and rolling closer, spreading through the night like ripples. Wang Mazi stiffened all over, abruptly pulling his wife into the shadow of the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '5388adb3386f4b268fb92f85b572bb3b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952502+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ae65508a60724e45ba4a3892a14dd23c', 'b862f0a472084a77beab20538052ac2e', '# Wang Mazi Returns to the Village', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '5c220a2ebf2846b78164e92f1735b109', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952502+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('1bf029e638684e2bb57cadc1c8b23fd6', 'b862f0a472084a77beab20538052ac2e', '**Time**: Late at night, around the third watch (approximately 11:45 PM)  
**Location**: The entrance of Wang Family Village, under the old locust tree  
**Weather**: A north wind howls, dark clouds obscure the moon, occasional sparse raindrops fall', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '750f0145b18648a49904b9c1092342d9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952503+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c528cc8bb5164513bddc2e594c3d4714', 'b862f0a472084a77beab20538052ac2e', 'In his left hand, he carried a bulging blue cloth bundle; his right hand tightly gripped the wrist of the woman beside him.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '7b251028e42f4308b22711f441787a3d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952503+00', NULL, NULL, NULL, NULL);
