INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c94fa15946484ebdb957756e35c07df8', 'b862f0a472084a77beab20538052ac2e', '## Scene One: The Old Locust Tree at the Village Entrance', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '998a35b114ef45e8b6d231617253e5db', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952504+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('92df1109339244c1967eb5a357f3da2c', 'b862f0a472084a77beab20538052ac2e', '### 【Conflict Foreshadowing】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '9c150ffbaa8347baa4373eaf85669409', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952504+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e0610617dca04da8b6991c0741b2e82e', 'b862f0a472084a77beab20538052ac2e', '"For the child." He added in a lowered voice. "He must be born in a clean place."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'a8b5dd5a389b4ecd956a5b396d29bd5a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952505+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('29f0b53410004f00acbe41ff3a85b43a', 'b862f0a472084a77beab20538052ac2e', '**Li Xiuying** (Wang Mazi''s wife) stumbled along, dragged by him. She was seven or eight years younger than Wang Mazi, with delicate yet haggard features; the fine wrinkles at the corners of her eyes were especially pronounced in the shadows. She was wrapped in a somewhat worn, floral-patterned cotton-padded jacket, her hair hastily pinned up with a wooden hairpin, a few stray strands stuck to her temples with sweat. She kept glancing back, her lips pressed together until they turned pale, her other hand unconsciously protecting her lower abdomen—which was slightly rounded, showing a pregnancy of about four or five months.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'ad81c61f1ce546f9a811bb2d8c37bcee', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952505+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e907f227285e4f578efdc70209a62d7d', 'b862f0a472084a77beab20538052ac2e', '"But the villagers..." Li Xiuying took the flatbread but didn''t eat it, her fingers unconsciously pinching its edge. "What if they ask about all these years..."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'b01c8132deec449383375bd2427c7928', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952506+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('5ad82ac458214dbb863c02588c98bd95', 'b862f0a472084a77beab20538052ac2e', '"Just say we ran a small business in the provincial capital and lost it all." Wang Mazi cut her off, his tone resolute. He stood up, slapping the dirt off his trouser legs, his movements carrying a fierce determination. "Remember, Xiuying, we know nothing. Not a single word about the ledger."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'b37160635d1d4dfa83904c2607096cfc', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952506+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c1aef2b30db94ff5ae0f14f169d7dedb', 'b862f0a472084a77beab20538052ac2e', '**Wang Mazi''s** footsteps came to an abrupt halt beneath the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c271867cecf8451b822ce0f61191ea1d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952506+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('a16676a3af664e769cb107ff19154ec5', 'b862f0a472084a77beab20538052ac2e', 'Wang Mazi did not answer immediately. He crouched down, rummaged in the bundle, and pulled out an oil-paper package containing half a stiff, hard pancake. He broke off a small piece and handed it to his wife, then gnawed on an even smaller piece himself, chewing slowly, his eyes never leaving the road leading into the village.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'ef2c4ff2f2bb4c1abe36e4a68ed92708', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952508+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('64d2cb96f09341ad9a9bcccb5acc872f', 'b862f0a472084a77beab20538052ac2e', '"Youfu…" her voice trembled, "do we have to come back now? Couldn''t we wait until daybreak to enter the village?"', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'f1a17f2460114bb4bd1a3e857f689a6b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:23:17.923937+00', '2026-03-01 08:59:02.691825+00', '2026-03-01 09:23:17.952509+00', NULL, NULL, NULL, NULL);
