INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c1bc2604c5c044f7b2ba79453c1228c7', 'b862f0a472084a77beab20538052ac2e', '# Wang Mazi Returns to the Village', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '392c0d44fc274b3b93c3c58e258de88f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356334+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9d522376cc0f477fa8646ffdbdcd93a5', 'b862f0a472084a77beab20538052ac2e', '## Scene One: The Old Locust Tree at the Village Entrance', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '543539e9ea0c43e2b9fca0c2cfcccc16', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356336+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('43c12f7163c3493dae2998450b53cb71', 'b862f0a472084a77beab20538052ac2e', '**Wang Mazi** (given name Wang Youfu) approaches from the far end of the dirt road, his steps heavy and hurried. He appears to be in his early forties, tall and lean with a slightly stooped back, wearing a faded navy-blue cotton jacket with frayed cuffs. The pockmarks on his face are barely discernible in the dim light, but his eyes are unusually bright—the kind of gaze belonging to someone long accustomed to life on the road, seasoned by the world. Yet now, they are mixed with weariness, anxiety, and a trace of barely perceptible wariness.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '5ed2826f626943109fb8ea1dcefc7eb3', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356337+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('5cf16ced5f4540ab96d1c33ed8edc1d6', 'b862f0a472084a77beab20538052ac2e', 'The north wind whirls sand, soil, and dead leaves; the air is thick with the damp smell of earth and a faint, distant odor of animal pens. Further away, the dark, hulking silhouette of the mountains lies like a great beast crouching, silently watching over this village whose peace is about to be shattered.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '5fba8d9672df41569799dfaab1d0c767', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356337+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('562d45ebe6114d62aaccda35e114fef5', 'b862f0a472084a77beab20538052ac2e', 'The century-old locust tree at the village entrance claws wildly in the night wind, its withered branches swaying like ghostly hands, casting fragmented, flickering shadows. Faded remnants of New Year couplets pasted on the trunk rustle loudly in the wind, like someone whispering in a low voice. The dirt road leading into the village is pitted and uneven; puddles reflect not a single glimmer of starlight. Only the faint, yellowish glow of oil lamps seeps through the window lattices of a few scattered households in the distance, trembling in the ink-black night.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'b5dd8e770c0340c0ad6ae7a383de6eb6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356341+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2cd61bffbb9b49418399782b3b701456', 'b862f0a472084a77beab20538052ac2e', '### 【Character Entrance】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c70cbd23b8014cbf9a9de5df639b1fd9', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356343+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('46e68c2a03dc4e4ead609167f769adb7', 'b862f0a472084a77beab20538052ac2e', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'dff4db96b61f437ebc70d3d2566995db', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 09:28:45.332919+00', '2026-03-01 09:23:19.243047+00', '2026-03-01 09:28:45.356345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('f94fdc76961647b38f4c9b78b8c578ef', 'b862f0a472084a77beab20538052ac2e', 'In his left hand, he carried a bulging The bedroll, while his right hand tightly gripped the wrist of the woman beside him.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '1102d3d5dd494c3f8ad38955f1cb6288', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('3ca481832609422ca3736e789a43400f', 'b862f0a472084a77beab20538052ac2e', '**Molly** (Wang Mazi''s wife) was dragged along, stumbling. She was seven or eight years younger than Wang Mazi, with delicate yet haggard features; the fine wrinkles at the corners of her eyes were especially pronounced in the shadows. She was wrapped in a somewhat worn floral-patterned cotton-padded jacket, her hair hastily tied up with a wooden hairpin, a few stray strands stuck to her temples with sweat. She kept looking back, her lips pressed together until they were pale, her other hand unconsciously protecting her lower abdomen—which was slightly rounded, indicating a pregnancy of about four or five months.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'd36fa65bf27b4cf8967827f17db5c25c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('4f414dc77dcb41d8abb5d2504a9d3048', 'b862f0a472084a77beab20538052ac2e', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '3f431bb1d51d459990d212b2d7e32edd', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0758cbfa236344eca77f48fd7f57681a', 'b862f0a472084a77beab20538052ac2e', '### 【Action and Emotional Details】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '9e30d7f211f1465ba0df380b10329c7a', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2fd6980f93a647318a1b094d300d3f77', 'b862f0a472084a77beab20538052ac2e', '**Wang Mazi**''s footsteps came to an abrupt halt beneath the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '3f29fe44a85f4edfa1856226ec4ffb38', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('5b2608e6985247f3a109df7bde222f16', 'b862f0a472084a77beab20538052ac2e', 'He released his wife''s wrist and turned to look back the way they had come. The dirt road stretched empty into the distance, with only the wind''s mournful howl. Yet he still squinted and stared for a long time, his Adam''s apple bobbing up and down as if confirming something. Sweat trickled down his temples, leaving a damp trail on his cheekbones.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '5c45650433a64eb3a5bfcdb14d709fad', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('a2780e1ff562403ba0e97d2d02202914', 'b862f0a472084a77beab20538052ac2e', '"No one''s following," he said in a low voice, more to convince himself. His voice was hoarse, parched from the long journey.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '724df02cdedf4fc1a8de275c2a03b711', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('215029367fa548929888509a5d26ce44', 'b862f0a472084a77beab20538052ac2e', '**Molly** leaned against the locust tree''s rough trunk, panting, her chest heaving. She raised a hand to wipe her face, unsure if it was rain or tears.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '69a47557905d4bf6a5f3d827565841fb', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e9296fee4cec4307a7bb73790b1e9ff6', 'b862f0a472084a77beab20538052ac2e', '"Youfu…" her voice trembled, "Do we have to come back now? Can''t we wait until daybreak to enter the village?"', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '2e7037d093d64dca987070ee0d3faf3c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:44:16.772013+00', '2026-03-01 09:44:16.772013+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('52d31d3d241b44448a5af5a352772551', '2312e0a93a6b4c8da66e19f864632e1b', '「夜明けまで待てない。」彼はようやく口を開き、クズクズになった餅が口元からこぼれ落ちた。「町の連中が……帳簿がなくなったのに気づいたら、真っ先にここを探しに来る。」', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '9d6e9b8d87e7498ab95d8b76a075915a', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:47:46.47252+00', '2026-03-01 09:47:46.47252+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('f1cee4e9ee334a479fea130eb5eea1e4', 'ada3637a24de44db91c1359958e586a5', '"But the villagers..." Molly took the pancake but didn''t eat it, her fingers unconsciously pinching its edge. "What if they ask about all these years..."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c5df27e3b6004b5cb7ca278e017a85fd', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('aaee57863cd742d5a0ec94d5837d9c9c', 'ada3637a24de44db91c1359958e586a5', '"Just say we ran a small business in the provincial capital and lost it all." Wang Mazi cut her off, his tone resolute. He stood up, patted the dirt off his trouser legs, his movements carrying a fierce determination. "Remember, Xiuying, we know nothing. Not a single word about the ledger."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '7c4e7337bbc748c2a2ccf767cd066db9', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('1b901d7cd7c648f39d6fff11a589cf90', 'ada3637a24de44db91c1359958e586a5', 'Molly lowered her head, her fingers moving to her lower abdomen, gently stroking it. Wang Mazi saw this gesture; his eyes softened for an instant, but then hardened again.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'a184f06cbc9a4495ba8e38e22d238960', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ad00b05feace4b10bcee6cf20ff87174', 'ada3637a24de44db91c1359958e586a5', '"For the child." He added in a lowered voice. "He must be born in a clean place."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'fdc7c684f21f44a68f6eb61f7ab307f2', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('924448c418d14ca0ad545096e002d651', 'ada3637a24de44db91c1359958e586a5', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'bdc23a9cce5748c5bae84e4f357dfbcd', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('52e105366a1d41e8a5ea40af209244b4', 'ada3637a24de44db91c1359958e586a5', '### 【Conflict Foreshadowing】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '7372f53d2c4949bea4941c2a044df6d6', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('a2156e297c924bbfb4f49f71348551ff', 'ada3637a24de44db91c1359958e586a5', 'At that very moment, the sound of barking dogs came from the distance.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c5b6fb22c4174c0090a2aec7192a6fe3', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('6060a93e1e144493b5cd4be31cf47af1', 'ada3637a24de44db91c1359958e586a5', 'Not just one, but one after another, starting from the east end of the village and spreading through the night like ripples. Wang Mazi stiffened all over, abruptly pulling his wife into the shadow of the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'fe803f64c0f648b4aed12e8c43382953', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('18191ff6a3d543c7a5dc0496d5b20d20', 'b99582ef92864d0dbc119d4ac347b087', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '0b8f5778b0bd4549b08e155e2e3b2f65', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602078+00', NULL, NULL, NULL, NULL);
