INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c02e3fb67be24b77ae16f7356205e7bc', 'd7025af9b3764cb4a769be8250b0bf1d', 'Mason: No one followed.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'cf93e279cd2143059abe66164c0b2a4d', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:47:09.094622+00', NULL, NULL, NULL, NULL);
