INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e51646e7700a477790a1636c005aeca6', 'b99582ef92864d0dbc119d4ac347b087', '## Scene One: The Old Locust Tree at the Village Entrance', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '05a7c7ff96974d6a9883fc5b2f187b00', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602073+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d68d25ea6416463094ed65e9b2dc99eb', 'b99582ef92864d0dbc119d4ac347b087', '### 【Conflict Setup】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '0aef7f83d3f64b2486a07b1e28fd2161', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602078+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('a48a3d66f306465c8d96401716340ba4', 'b99582ef92864d0dbc119d4ac347b087', '**Molly** (Wang Mazi''s wife) stumbled along, dragged by him. She was seven or eight years younger than Wang Mazi, with delicate but haggard features; the fine wrinkles at the corners of her eyes were especially pronounced in the shadows. She was wrapped in a somewhat worn, floral-patterned cotton-padded jacket, her hair hastily pinned up with a wooden hairpin, a few stray strands stuck to her temples with sweat. She kept looking back, her lips pressed together until they were pale, her other hand unconsciously protecting her lower abdomen—which was slightly rounded, showing a pregnancy of about four or five months.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '1d84febf67fb4b94b7ed12612e00cffb', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602079+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d04a801a2d66431db5fe17a62e328d99', 'b99582ef92864d0dbc119d4ac347b087', 'The north wind whirls sand, soil, and dead leaves in eddies. The air is thick with the damp smell of earth and a faint, distant odor of animal pens. Further away, the dark, indistinct outlines of the mountains crouch like giant beasts, silently watching over this village whose peace is about to be shattered.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '2154742f4c9848eeadc4d6c25a985a3d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.60208+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('afe39bb64ae643799db00f5598f9a65a', 'b99582ef92864d0dbc119d4ac347b087', 'Not from one house, but one after another, starting from the east end of the village and rolling closer, spreading through the night like ripples. Wang Mazi stiffened all over, abruptly pulling his wife into the shadow of the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '4262ee88873241b69a3b0d520359f864', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.60208+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('bcdb5eeac7294776aeccb2f46f76c537', 'b99582ef92864d0dbc119d4ac347b087', '**Wang Mazi**''s footsteps came to an abrupt halt beneath the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '4d8d976574d9449e85996e6c24d8ac57', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602081+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('7a5a5b5905d8426aad71ce518d3a4de6', 'b99582ef92864d0dbc119d4ac347b087', '**Molly** leaned against the locust tree''s rough trunk, panting, her chest heaving. She raised a hand to wipe her face, unsure if it was rain or tears.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '53ac35845f4d4567b7574b013a641717', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602081+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0837e4b94ec74da9b303346d61aacb7d', 'b99582ef92864d0dbc119d4ac347b087', 'The century-old locust tree at the village entrance claws at the night wind, its withered branches swaying like ghostly hands, casting fragmented, flickering shadows. Faded remnants of Spring Festival couplets pasted on the tree trunk rustle loudly in the wind, like someone whispering in a low voice. The dirt road leading into the village is pitted and uneven; puddles reflect not a single glimmer of starlight. Only the faint, yellowish glow of oil lamps seeps through the window lattices of a few scattered households in the distance, trembling in the ink-black night.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '58b19b688c2e4c24b11564a13fcb48d5', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602082+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('626dc910ee7e496d939bcfc2a8827a72', 'b99582ef92864d0dbc119d4ac347b087', '"For the child." He added, lowering his voice. "He must be born in a clean place."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '7cce57e706434942bb91d34728f1a252', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602083+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0d648b2945764181a71b0b880bf760e9', 'b99582ef92864d0dbc119d4ac347b087', 'Molly lowered her head, her fingers moving to her lower abdomen, gently stroking. Wang Mazi saw this gesture; his eyes softened for an instant, then hardened again.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '7d53a03a9ed942ef887b1404e47f9238', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602084+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ccc8c29fc2684cbfa720df9ccf732904', 'b99582ef92864d0dbc119d4ac347b087', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'b52531834dfb46f9a79a4e5fbfefae79', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602085+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c00c2eb5515747ef8c2511dbadf80366', 'd7025af9b3764cb4a769be8250b0bf1d', 'Molly: Youfu... do we really have to come back at this hour? Can''t we just wait until daybreak to enter the village?', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '804387f0c6e34b22b8230a0d7aed71a0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:47:17.464988+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('1240ea52125c4fb7a20e8b491e955b4e', 'd7025af9b3764cb4a769be8250b0bf1d', 'Molly: But the villagers... what if they ask about all these years...', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'dfdac244f898499da2ac5ab009d99fa7', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:48:33.073225+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('55a3bf5c7770435ea149f16c410462e8', 'ada3637a24de44db91c1359958e586a5', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '69e0f1fb0f43457f80f154b13958feb7', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.06037+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('59cfff052a424d29944c99a3cc0ffc9f', 'b99582ef92864d0dbc119d4ac347b087', 'He released his wife''s wrist and turned to look back the way they had come. The dirt road stretched empty to its end, with only the wind''s mournful howl. Yet he still squinted and stared for a long time, his Adam''s apple bobbing up and down as if confirming something. Sweat trickled down his temples, leaving a damp streak on his cheekbones.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '5ba58918a6164375a715594bd9d42abc', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602082+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e545c92ba0d34ae69b8c503f561c4d67', 'b99582ef92864d0dbc119d4ac347b087', '"Just say we ran a small business in the provincial capital and lost money." Wang Mazi cut her off, his tone resolute. He stood up, patted the dirt off his trouser legs, his movements carrying a fierce determination. "Remember, Xiuying, we know nothing. Not a single word about the ledger."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '5d6eaafd1ce04dd8813d3e5fccf21c6b', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602083+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('6bd060d018bb46699a9f23cd04351c97', 'b99582ef92864d0dbc119d4ac347b087', '"Youfu…" her voice trembled, "Do we have to come back now? Can''t we wait until daybreak to enter the village?"', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '72f354d527be4b85a61a54577d2fbb66', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602083+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('3f62181673214e208e3f80a7bfdc6b3c', 'b99582ef92864d0dbc119d4ac347b087', '**Wang Mazi** (real name Wang Youfu) approached from the end of the dirt road, his footsteps heavy and hurried. He was around forty years old, tall and lean, with a slightly stooped back, wearing a faded navy blue cotton jacket whose cuffs were frayed. In the dim light, the pockmarks on his face were hard to make out, but his eyes were unusually bright—the kind of eyes belonging to someone who had long been on the road and seen the world, yet now they were mixed with weariness, anxiety, and a trace of barely perceptible wariness.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'a54fa630c24a43bfa7ad15314598d497', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602085+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('04f9fd3bad2744598d79c4b309f6d637', 'b99582ef92864d0dbc119d4ac347b087', '"No one''s following," he said in a low voice, more to convince himself. His voice was hoarse, parched from the long journey.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'b2fd83b040a243a7be73e70bee9cfc34', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602085+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c3f616f47dbd4c5da4129085a299a6f0', 'b99582ef92864d0dbc119d4ac347b087', 'At that moment, the sound of barking dogs came from the distance.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c334d638609d4d9b88ad894c237741db', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602086+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c3dd51e0766a48d0b872653a65bfe6f6', 'b99582ef92864d0dbc119d4ac347b087', 'He carried a bulging The bedroll in his left hand, his right hand gripping the wrist of the woman beside him tightly.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c367dbe023e14c6c8b882a7fff871b47', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602086+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d2062c56aed04a41b65fa8e207ca4a5b', 'b99582ef92864d0dbc119d4ac347b087', '### 【Environmental Description】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'c76a5d4eb56f4538a583f7ef43027ed6', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602087+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('1be6a18943274c3e97437deec17bd32b', 'b99582ef92864d0dbc119d4ac347b087', '**Time**: Late at night, around the third watch of the night (approximately 11:45 PM)  
**Location**: Out by the county line oak  
**Weather**: A north wind howls, dark clouds obscure the moon, with occasional scattered raindrops pelting down', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'cce4f649881f4c1db726f00112473a68', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602087+00', NULL, NULL, NULL, NULL);
