INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ccfa34753be642178b6f1643447087b5', 'b99582ef92864d0dbc119d4ac347b087', '"We can''t wait till dawn." He finally spoke, crumbs falling from the corner of his mouth. "Those people in the city... if they find the ledger is missing, this is the first place they''ll come looking."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'ecfaa9bdb068400eb94a35852f4c28b4', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:02:30.57455+00', '2026-03-01 10:28:51.544183+00', '2026-03-01 11:02:30.602088+00', NULL, NULL, NULL, NULL);
