INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9075630fcb5a475c84b6ad9c705eba88', 'd7025af9b3764cb4a769be8250b0bf1d', 'Mason: For the child. He must be born in a clean place.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '3024e57ec5cc42edba75584e22ef6f12', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:48:23.435916+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('638666b3f24745f4bebdf158c18f6061', 'd7025af9b3764cb4a769be8250b0bf1d', 'Mason: Just say I was running a small business in the provincial capital and lost money. Remember, Xiuying, we don''t know anything. Not a word about the account books.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '7d7fab5397cd4f86a73a96a668357779', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:48:34.029804+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('38436939162546509332196320601b47', 'ada3637a24de44db91c1359958e586a5', '# Wang Mazi Returns to the Village', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '2f7a176a24b64a6183e7c851b9e557e0', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060367+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('235692eb58dd433689eacae6ebc67aa1', 'd7025af9b3764cb4a769be8250b0bf1d', 'Molly (Mason''s wife) was dragged along, stumbling. She was seven or eight years younger than Mason, with delicate yet haggard features; the fine wrinkles at the corners of her eyes were especially pronounced in the shadows. She was wrapped in a somewhat worn, floral-patterned cotton-padded jacket, her hair hastily pinned up with a wooden hairpin, a few stray strands stuck to her temples with sweat. She kept glancing back, her lips pressed pale, her other hand unconsciously protecting her lower abdomen—which was slightly rounded, showing a pregnancy of about four or five months.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '7d6ed3e27fe14c65b4fcb83c0b8f18de', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:48:13.121292+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('8437b34f5c8d450dbbcf707aab509b55', 'ada3637a24de44db91c1359958e586a5', 'The north wind whirls sand, soil, and dead leaves; the air is thick with the smell of damp earth and a faint, distant odor of livestock pens. Further away, the dark, indistinct outlines of mountain ranges crouch like giant beasts, silently watching this village whose peace is about to be shattered.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '365757e4e01540e9b8ddeedf00de964c', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060368+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('db2180c49fd645e192dcd2238d569bc2', 'ada3637a24de44db91c1359958e586a5', '**Wang Mazi** (given name Wang Youfu) walks from the end of the dirt road, his steps heavy and hurried. He appears to be in his early forties, tall and lean with a slightly hunched back, wearing a faded navy-blue cotton-padded jacket with frayed cuffs. The few pockmarks on his face are hard to make out in the dim light, but his eyes are unusually bright—the kind of gaze possessed by someone long accustomed to traveling and worldly affairs, yet now mixed with weariness, anxiety, and a trace of barely perceptible wariness.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '43adbdaa7dd8413888fcc30842683e70', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060368+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2706f1357bbb462ba7604000072d9bf6', 'ada3637a24de44db91c1359958e586a5', '**Time**: Late at night, around the third watch (approximately 11:45 PM)  
**Location**: Out by the county line oak  
**Weather**: A north wind howls, dark clouds obscure the moon, occasional scattered raindrops fall', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '50829387e13448d7b40118f29e1c7117', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060369+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('8b66446dbf13443d8922f73869eedb4a', 'ada3637a24de44db91c1359958e586a5', 'Molly lowered her head, her fingers moving to her lower abdomen, gently stroking it. Wang Mazi saw this gesture; his gaze softened for an instant, but then hardened again.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '788bb6dbbac64e428f1a419678804c46', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.06037+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2fa239e8e8c74bd3af74b874e9ef86da', 'ada3637a24de44db91c1359958e586a5', 'In his left hand, he carried a bulging The bedroll, while his right hand tightly gripped the wrist of the woman beside him.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '7a33dd804dc146b2944f7a806690baef', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.06037+00', NULL, NULL, NULL, NULL);
