INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('56fcc4613b404a37b5b3795f6dc6e0ca', 'ada3637a24de44db91c1359958e586a5', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '905e430ea0ff4c69bab46e7060c8f410', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060372+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('8bacd94b9e6c441895b07b28f240dbe9', 'ada3637a24de44db91c1359958e586a5', 'The century-old locust tree at the village entrance claws wildly in the night wind, its withered branches swaying like ghostly hands, casting fragmented, flickering shadows. Faded remnants of New Year couplets pasted on the tree trunk rustle loudly in the wind, like someone whispering in a low voice. The dirt road leading into the village is pitted and uneven; puddles reflect not a single starlight. Only the faint, yellowish glow of oil lamps seeping through the window lattices of a few scattered households in the distance trembles within the ink-black night.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '932e4d37e87b428888bfec3c7dd9d04e', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060372+00', NULL, NULL, NULL, NULL);
