INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('71082fee213f4864b7ca24f7ea1e49e9', 'ada3637a24de44db91c1359958e586a5', '"Youfu…" her voice trembled, "Do we have to come back now? Can''t we wait until daybreak to enter the village?"', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '0362490539e44335bd5b624b3e9f043a', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060362+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('f81dc6bc526e4f429d3129204ad24366', 'ada3637a24de44db91c1359958e586a5', '**Wang Mazi**''s footsteps came to an abrupt halt beneath the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '1717f19d58ba4658a8028acc3553cdf2', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060366+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('4c46a1e0834043fcbe78d79b8b26ef1c', 'ada3637a24de44db91c1359958e586a5', 'Wang Mazi didn''t answer immediately. He crouched down, rummaged in the bundle, and pulled out an oil-paper package containing half a piece of rock-hard flatbread. He broke off a small piece and handed it to his wife, then gnawed on an even smaller piece himself, chewing slowly, his eyes never leaving the road leading into the village.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '2746bad796b0452d9018f34ec2ba3831', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060367+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9dab901844b44473ad8c6ea3bf8667c7', 'ada3637a24de44db91c1359958e586a5', '"No one''s following," he said in a low voice, more to convince himself. His voice was hoarse, parched from the long journey.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '45ceebfc21af4f57a33aa513db4abdfa', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060369+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d395f297fe8b4e86bac8a7bfdac8d820', 'ada3637a24de44db91c1359958e586a5', '**Molly** leaned against the locust tree''s rough trunk, panting, her chest heaving. She raised a hand to wipe her face, unsure if it was rain or tears.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '7c0e595748d44f5bb1cdc0f554959208', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060371+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0f387c88a1654fdbb848b23c88738fc2', 'ada3637a24de44db91c1359958e586a5', '### 【Action and Emotional Details】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '979136bd76984e9598e16fa56541df75', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060372+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('040061a6d5f64371a21b8638f7c0cb4b', 'ada3637a24de44db91c1359958e586a5', 'He released his wife''s wrist and turned to look back the way they had come. The dirt road stretched empty to its end, with only the wind''s mournful howl. Yet he still squinted and gazed for a long time, his Adam''s apple bobbing up and down as if confirming something. Sweat trickled down his temples, leaving a damp trail on his cheekbones.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'a640a7f3d7af4c6d83d8b77bf82e505f', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060373+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('7f7d4a32e8b84a509deba4617a7d6441', 'ada3637a24de44db91c1359958e586a5', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'fa6640e229eb4e079808caf3a45194cd', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060377+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e06b5faeca2d45f1bc9f92d4945cb540', 'ada3637a24de44db91c1359958e586a5', '**Molly** (Wang Mazi''s wife) was dragged along, stumbling. She was seven or eight years younger than Wang Mazi, with delicate yet haggard features; the fine wrinkles at the corners of her eyes were especially pronounced in the shadows. She was wrapped in a somewhat worn, floral-patterned cotton-padded jacket, her hair hastily tied up with a wooden hairpin, a few stray strands stuck to her temples with sweat. She kept looking back, her lips pressed together until they were pale, her other hand unconsciously protecting her lower abdomen—which was slightly rounded, showing a pregnancy of about four or five months.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'fb38abe776f14d82a245a924d155d3cb', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060378+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('c20f6ec8654342f6a3918e9581d6eab7', 'ada3637a24de44db91c1359958e586a5', '# Wang Mazi Returns to the Village', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '4983539a1f58449fa2979e6508dfb7b7', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('5dc3c1e66d354f73ad86c007efea076c', 'ada3637a24de44db91c1359958e586a5', '## Scene One: The Old Locust Tree at the Village Entrance', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'ed3294f4b06f4815a062ceec4cf30758', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('6bfe63396ef544a49369d2f20d6eec0a', 'ada3637a24de44db91c1359958e586a5', '**Time**: Late at night, around the third watch (approximately 11:45 PM)  
**Location**: Out by the county line oak  
**Weather**: A north wind howls, dark clouds obscure the moon, occasional sparse raindrops fall', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '39f41e5268dd4081b0a24666fbbce309', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
