INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('9546c8d7a3d04c1c95cdd0ea1cabd7d0', 'ada3637a24de44db91c1359958e586a5', '### 【Environmental Description】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'b8adeb9edd2845f9945db14602d9b5ca', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('487b64be1b44437ab2e8568f8243088f', 'ada3637a24de44db91c1359958e586a5', 'The century-old locust tree at the village entrance claws at the night wind, its withered branches swaying like ghostly hands, casting fragmented, wavering shadows. Faded remnants of Spring Festival couplets pasted on the tree trunk rustle loudly in the wind, like someone whispering in a low voice. The dirt road leading into the village is pitted and uneven; puddles reflect not a single glimmer of starlight. Only the faint, yellowish glow of oil lamps seeps through the window lattices of a few scattered households in the distance, trembling in the ink-black night.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '25eb212f51814e87b75aa3efb3a016d9', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('f10a338f3f424d0f989d42ed743d2da2', 'ada3637a24de44db91c1359958e586a5', 'The north wind whirls dust and dead leaves; the air is thick with the damp smell of earth and a faint, distant odor of livestock pens. Further away, the dark outlines of the mountains crouch like giant beasts, silently watching over this village whose peace is about to be shattered.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'e042c50cc03345e9a1145b6a2a2ba41c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('7457436bd4904ee986e62fd902c0e2a1', 'ada3637a24de44db91c1359958e586a5', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '856b05ff08e7412cbd68acb09c0fa408', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0f44c0eb452c492ba6832ec4de69220b', 'ada3637a24de44db91c1359958e586a5', '### 【Character Entrance】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'f83a639ce25f4ad38a7276e3503150dc', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('aed22a6572f14d06b8c435f2cf069173', 'ada3637a24de44db91c1359958e586a5', '**Wang Mazi** (real name Mason Weaver) approaches from the end of the dirt road, his steps heavy and hurried. He appears to be in his early forties, tall and lean with a slightly hunched back, wearing a faded navy-blue cotton-padded jacket with frayed cuffs. The pockmarks on his face are indistinct in the dim light, but his eyes are unusually bright—the kind of gaze belonging to someone long accustomed to traveling and worldly affairs, yet now mixed with weariness, anxiety, and a trace of barely perceptible wariness.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '3dd2738d4bff4df0849c1bd1ca6e0869', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2fb4ceb1c0254eb28367404d59254c32', 'ada3637a24de44db91c1359958e586a5', 'Wang Mazi did not answer immediately. He squatted down, fished out an oil-paper package from his bundle, which contained half a piece of rock-hard flatbread. He broke off a small piece and handed it to his wife, then gnawed on an even smaller piece himself, chewing slowly, his eyes never leaving the road at the village entrance.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'e9fecf8d26b44801bafdebdba8663419', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:17:03.281832+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('7aa5a5a87ecf4813b00228e7178668d2', 'ada3637a24de44db91c1359958e586a5', 'Not from one house, but one after another, starting from the east end of the village and spreading through the night like ripples. Wang Mazi stiffened all over, abruptly pulling his wife into the shadow of the locust tree.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'd42f79b46483404cb179a283bb3db068', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060375+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('43f7ad81d8914fe3a18b2efaf71e8fa0', 'ada3637a24de44db91c1359958e586a5', 'In his left hand, he carried a bulging The bedroll, while his right hand tightly gripped the wrist of the woman beside him.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '1cd44200829a4d50841015f4ef3b1ace', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('157dc29738a54808babe82aa14540b3b', 'ada3637a24de44db91c1359958e586a5', '**Molly** (Wang Mazi''s wife) stumbled along, dragged by him. She was seven or eight years younger than Wang Mazi, with delicate yet haggard features; the fine wrinkles at the corners of her eyes were particularly pronounced in the shadows. She was wrapped in a somewhat worn floral-patterned cotton-padded jacket, her hair hastily pinned up with a wooden hairpin, a few stray strands stuck to her temples with sweat. She kept looking back, her lips pressed together until they turned pale, her other hand unconsciously protecting her lower abdomen—which was slightly rounded, showing a pregnancy of about four or five months.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'e33fb034e8c5463aa1c0dbf77cc5316a', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
