INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('afaa3fff0f3f4da2ae40f66113d80d34', 'ada3637a24de44db91c1359958e586a5', 'He released his wife''s wrist and turned to look back the way they had come. The dirt road stretched empty into the distance, with only the wind''s mournful howl. Yet he squinted and stared for a long time, his Adam''s apple bobbing up and down as if confirming something. Sweat trickled down his temples, leaving a damp trail on his cheekbones.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '772c2d3974b547cdbc91a2177b3c5373', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('99549f67bf1145818db3071cfc58f23d', 'ada3637a24de44db91c1359958e586a5', '"No one''s following," he said in a low voice, more to convince himself. His voice was hoarse, parched from the long journey.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '097b4de4291b4b309521cdb16f8ca3cf', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('77c14fc75d4942c6a278b04392e69837', 'ada3637a24de44db91c1359958e586a5', '**Molly** leaned against the locust tree''s rough trunk, panting, her chest heaving. She raised a hand to wipe her face, unsure if it was rain or tears.', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'e1a3a641ad464e95bbc8228debe9740a', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('1e9919a065904e7ab39869c84a03d46b', 'ada3637a24de44db91c1359958e586a5', '"Youfu…" her voice trembled, "do we have to come back now? Can''t we wait until daybreak to enter the village?"', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '56eac980ea104b45982d0257952c93ea', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 11:13:44.082345+00', '2026-03-01 11:13:44.082345+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('cebc40699ae944d59eab353e65a50013', 'd7025af9b3764cb4a769be8250b0bf1d', 'Mason crouched down, fished an oil-paper package from his bundle, which contained half a piece of rock-hard flatbread. He broke off a small piece and handed it to his wife, then gnawed on an even smaller piece himself, chewing slowly, his eyes never leaving the road at the village entrance.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'd1f37e32887e4ec88c6fc34a5ddbc89f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:47:53.86676+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('a5813feef9304ce7be95a02dfc70846b', 'd7025af9b3764cb4a769be8250b0bf1d', 'Molly leaned against the locust tree''s rough trunk, panting, her chest heaving. She raised a hand to wipe her face, unsure if it was rain or tears.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '7cb54c28c00b49eda09d0c220d221397', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:47:59.006782+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('629a4c3075f940dfa169e4d6363d6629', 'd7025af9b3764cb4a769be8250b0bf1d', 'Just then, the distant sound of barking dogs arose. Not from one house, but in waves, starting from the east end of the village and rolling closer, spreading through the night like ripples. Wang Mazi''s whole body stiffened, and he yanked his wife into the shadow of the locust tree.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '1e2a58d2990f4fe7a0678e6bc17ed392', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:47:27.688052+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e0ce2a62a28d4346a9422d11cd9b1b0f', 'd7025af9b3764cb4a769be8250b0bf1d', 'Molly lowered her head, her fingers touching her lower abdomen, gently stroking. Wang Mazi saw this gesture; his gaze softened for an instant, then hardened again immediately.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '99c3e99eb178486e939a2d39a00a3cf6', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:47:39.979031+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('ad7f5f9543c2420f889474658bc55bd3', 'd7025af9b3764cb4a769be8250b0bf1d', 'Mason stood up, dusted off the dirt on his pant legs, his movements carrying a fierce determination.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '66b5c96d85d9480aa56b19cf82e0196b', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:47:47.466615+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('e350357ad7d341218efa4cbc76a23202', 'd7025af9b3764cb4a769be8250b0bf1d', 'Mason''s footsteps came to an abrupt halt beneath the locust tree. He released his wife''s wrist and turned to look back the way they had come. The dirt road stretched empty to the horizon, nothing but the wind''s mournful howl. Yet he squinted into the distance for a long while, his Adam''s apple bobbing up and down as if confirming something. Sweat trickled from his temples, leaving a damp trail across his cheekbones.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '9884f9a94edc4063bde2cc2b195e0cbd', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:48:04.588488+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2a4cf7c9527b448c993d049fbd304264', 'ada3637a24de44db91c1359958e586a5', '---', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'e11bf7c993284b70b53b86063173879d', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060376+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('0c8beb4c39ae4355ac0ca2c8331933e8', 'ada3637a24de44db91c1359958e586a5', '"For the child." He added in a lowered voice. "He must be born in a clean place."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'f0518edfb25b43de967cd2ce83ab8b59', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060376+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('2108adfc58bd4f92a0e315af41040626', 'ada3637a24de44db91c1359958e586a5', '"Just say we ran a small business in the provincial capital and lost it all." Wang Mazi cut her off, his tone resolute. He stood up, patted the dirt off his trouser legs, his movements carrying a fierce determination. "Remember, Xiuying, we know nothing. Not a single word about the ledger."', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'f28d77549efc495ab1af3dca9e3df8cc', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060377+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('d2792fed4908481eb0e265616c69179e', 'ada3637a24de44db91c1359958e586a5', '### 【Conflict Foreshadowing】', 'draft', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, 'fff8e50cbf14435f8dd2511aa379f912', 'default', 'default', NULL, NULL, NULL, 'v1', '2026-03-01 11:13:44.025052+00', '2026-03-01 11:10:52.717571+00', '2026-03-01 11:13:44.060378+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('8e613b3cdfa244e983aa73a042e63211', 'd7025af9b3764cb4a769be8250b0bf1d', 'The century-old locust tree at the village entrance clawed at the night wind, its withered branches swaying like ghostly talons, casting fragmented, wavering shadows. Faded remnants of spring couplets pasted on the tree trunk rustled in the wind, like someone murmuring in a low voice. The dirt road leading into the village was pitted and uneven; puddles reflected not a single star, with only the faint, trembling halos of dim oil lamps seeping through the window lattices of a few scattered households in the distance, quivering in the ink-black night. The north wind swirled with dust and dead leaves, the air thick with the damp smell of earth and a faint, distant odor of livestock from the pens. Further away, the dark, hulking silhouette of the mountains crouched like a giant beast, silently watching over this village whose peace was about to be shattered.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '553e0011b99546049f044fc35f2303a0', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:46:47.686224+00', NULL, NULL, NULL, NULL);
INSERT INTO public.translation_blocks (script_block_id, translation_project_id, translated_text, status, translation_notes, model_provider_id, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('b6c9ef2dec5249c3bbb2a808b9e59840', 'd7025af9b3764cb4a769be8250b0bf1d', 'Mason Weaver approached from the end of the dirt road, his footsteps heavy and hurried. He appeared to be in his early forties, tall and lean with a slightly stooped back, wearing a faded navy blue cotton jacket with frayed cuffs. The pockmarks on his face were indistinct in the dim light, but his eyes were unusually bright—the kind of gaze belonging to someone long accustomed to traveling and worldly affairs, yet now mingled with weariness, anxiety, and a trace of barely perceptible vigilance. In his left hand, he carried a bulging The bedroll, while his right hand gripped the wrist of the woman beside him.', 'reviewed', NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', 0, '8dc171e1956a479c8ec4d275a97fd55f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 12:20:34.852844+00', '2026-03-01 13:48:08.58807+00', NULL, NULL, NULL, NULL);


