INSERT INTO public.skill_runs (id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message, retry_count, skill_id, novel_id, chapter_id, input_hash, input_snapshot, status, output_json, raw_response, token_usage, cost_estimate, model_provider_id, model_name) VALUES ('96879a4c8f2b43c582b70e859184ed0f', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:19:15.497871+00', '2026-03-01 08:20:17.195735+00', NULL, NULL, NULL, NULL, 0, 'name_localization_suggest', 'novel_b831875078b348ffa5569429fdb4105c', NULL, NULL, '{"entity_count": 10, "target_language": "ja-JP"}', 'succeeded', '{"suggestions": [{"entity_id": "cd0aaef3eedb4e05a681c76a31daf8ea", "candidates": [{"name": "時代物", "rationale": "日本文学中描述特定历史时期作品的常用分类术语，符合日语读者对时代背景类作品的认知习惯", "naming_policy": "cultural_equivalent"}, {"name": "年代記", "rationale": "直译“年代”为日语汉字词汇，保留原意且符合日语表达", "naming_policy": "literal"}, {"name": "ネンダイ", "rationale": "音译中文发音，适合作为外来语风格的作品分类标签", "naming_policy": "transliteration"}]}, {"entity_id": "02c6ca68267e4cfebb74a10cc1e58530", "candidates": [{"name": "隠し帳面", "rationale": "日语中“隠し”可表达隐含、秘密之意，符合原文“隐含账本”的语境", "naming_policy": "cultural_equivalent"}, {"name": "暗示された帳簿", "rationale": "直译“隐含的账本”，清晰传达原文含义", "naming_policy": "literal"}, {"name": "ジャンベン", "rationale": "音译“账本”的近似发音，适合作为特殊道具的名称", "naming_policy": "transliteration"}]}, {"entity_id": "14c18eb154f14e02a4ce1fb37c2fd16f", "candidates": [{"name": "藍の風呂敷包み", "rationale": "用日本传统包袱布“風呂敷”替代“包袱”，蓝色布料符合日本传统色彩审美", "naming_policy": "cultural_equivalent"}, {"name": "青い布の包み", "rationale": "直译“蓝布包袱”，准确传达物品特征", "naming_policy": "literal"}, {"name": "ランプー・バオフ", "rationale": "音译中文发音，保留异域色彩", "naming_policy": "transliteration"}]}, {"entity_id": "4c9f5b9ef57a49e6a456bdec2f9dc8ce", "candidates": [{"name": "サスペンス", "rationale": "日语中直接使用外来语“suspense”表示悬疑类型，是日本读者最熟悉的分类", "naming_policy": "cultural_equivalent"}, {"name": "懸疑", "rationale": "保留汉字“懸疑”，日语中也可理解但较书面化", "naming_policy": "literal"}, {"name": "シュエンイー", "rationale": "音译中文发音，适合作为特殊风格标签", "naming_policy": "transliteration"}]}, {"entity_id": "7bebde2708144371a3f4b9700c46a755", "candidates": [{"name": "逃避行", "rationale": "日语中描述逃亡、逃避的常用文学术语，带有叙事性色彩", "naming_policy": "cultural_equivalent"}, {"name": "逃亡", "rationale": "直译“逃亡”，日语汉字完全相同且常用", "naming_policy": "literal"}, {"name": "タオワン", "rationale": "音译中文发音，适合作为作品风格标签", "naming_policy": "transliteration"}]}, {"entity_id": "8ca16755840b4a8881ff9faa43ffd4a0", "candidates": [{"name": "王 麻子（本名：王 有福）", "rationale": "保留中文姓名发音和汉字，日语读者可通过汉字理解“麻子”含义，同时保留本名信息", "naming_policy": "transliteration"}, {"name": "王 アザ（本名：王 ユウフク）", "rationale": "姓氏保留汉字“王”，“麻子”意译为“アザ”（痘痕/麻子），“有福”音译为ユウフク", "naming_policy": "literal"}, {"name": "お岩（本名：王 幸吉）", "rationale": "“お岩”是日本传统怪谈中面部有瑕疵的女性角色名，符合“麻子”特征；本名改为日本常见名“幸吉”保留“有福”的吉祥含义", "naming_policy": "cultural_equivalent"}]}, {"entity_id": "8cfda39c5a8f46e29e5d086af1bd61a4", "candidates": [{"name": "王家村の村口、老槐の木の下", "rationale": "直译所有元素，保留“王家村”“老槐树”等中文地名特征", "naming_policy": "literal"}, {"name": "王村の入り口、エンジュの古木の下", "rationale": "“王家村”简化为“王村”更符合日本地名习惯；“槐树”替换为日本常见的“エンジュ”（槐树同科植物）", "naming_policy": "cultural_equivalent"}, {"name": "ワンジャーツンの村入り口、古いフアイの木の下", "rationale": "音译“王家村”为ワンジャーツン，“槐树”音译为フアイ，保留中文发音特色", "naming_policy": "transliteration"}]}, {"entity_id": "a769281d8de44c91a2761ae276444d1a", "candidates": [{"name": "油紙包みの焼き餅", "rationale": "“烙饼”译为日本更常见的“焼き餅”，“油纸包”保留传统包装方式", "naming_policy": "cultural_equivalent"}, {"name": "油紙に包まれたロービン", "rationale": "直译“油纸包”，烙饼音译为ロービン并加注说明", "naming_policy": "literal"}, {"name": "ヨウジバオのラオビン", "rationale": "音译“油纸包”和“烙饼”，完全保留中文发音", "naming_policy": "transliteration"}]}, {"entity_id": "b5a3fa41e70a4d09bbdfa7b6b05f05b3", "candidates": [{"name": "ストーリー", "rationale": "日语中最常用的“story”外来语，指剧情、故事内容", "naming_policy": "cultural_equivalent"}, {"name": "劇情", "rationale": "直译“剧情”，日语汉字可理解但较中文化", "naming_policy": "literal"}, {"name": "ジューチン", "rationale": "音译中文发音，适合作为分类标签", "naming_policy": "transliteration"}]}, {"entity_id": "bb99d3ad26814961aa211fd6040527bf", "candidates": [{"name": "李 秀英（り しゅうえい）", "rationale": "保留中文姓名汉字，标注日语读音，是处理中文人名的常见方式", "naming_policy": "transliteration"}, {"name": "李 秀栄", "rationale": "姓氏保留汉字“李”，“秀英”改为日语常用女性名“秀栄”，读音相同但汉字微调", "naming_policy": "literal"}, {"name": "桜井 秀子（さくらい ひでこ）", "rationale": "改为日本常见姓氏“桜井”，名字“秀子”保留“秀”字并符合日本女性命名习惯", "naming_policy": "cultural_equivalent"}]}]}', '```json
