INSERT INTO public.skill_runs (id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message, retry_count, skill_id, novel_id, chapter_id, input_hash, input_snapshot, status, output_json, raw_response, token_usage, cost_estimate, model_provider_id, model_name) VALUES ('983599de19b54897b3ff2f30c52d8a8c', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 08:24:02.602143+00', '2026-03-01 08:25:04.232696+00', NULL, NULL, NULL, NULL, 0, 'name_localization_suggest', 'novel_b831875078b348ffa5569429fdb4105c', NULL, NULL, '{"entity_count": 10, "target_language": "en-US"}', 'succeeded', '{"suggestions": [{"entity_id": "cd0aaef3eedb4e05a681c76a31daf8ea", "candidates": [{"name": "Period Drama", "rationale": "在英语影视分类中，''年代''常对应''Period Drama''，指代特定历史时期的作品。", "naming_policy": "cultural_equivalent"}, {"name": "Era", "rationale": "直译''年代''为''Era''，简洁通用。", "naming_policy": "literal"}, {"name": "Niandai", "rationale": "音译保留中文原词，适合作为风格标签。", "naming_policy": "transliteration"}]}, {"entity_id": "8ca16755840b4a8881ff9faa43ffd4a0", "candidates": [{"name": "Pockmark Wang (born Wang Youfu)", "rationale": "''麻子''在英语文化中常译为''Pockmark''，姓氏''Wang''保留，符合英语昵称+本名的表述习惯。", "naming_policy": "cultural_equivalent"}, {"name": "Wang Mazi (born Wang Youfu)", "rationale": "音译''王麻子''为''Wang Mazi''，保留中文特色，括号内注明本名。", "naming_policy": "transliteration"}, {"name": "Scarface Wang (born Wang Youfu)", "rationale": "借用英语中''Scarface''（疤面）的类似绰号概念，更贴近目标文化对脸部特征绰号的认知。", "naming_policy": "cultural_equivalent"}]}, {"entity_id": "bb99d3ad26814961aa211fd6040527bf", "candidates": [{"name": "Li Xiuying", "rationale": "音译中文女性人名''李秀英''，符合英语中音译中文姓名的常规格式。", "naming_policy": "transliteration"}, {"name": "Grace Li", "rationale": "''秀英''含义近似''优雅/杰出''，选用''Grace''作为文化等价名，搭配姓氏''Li''。", "naming_policy": "cultural_equivalent"}, {"name": "Xiuying Li", "rationale": "采用名在前、姓在后的音译格式''Xiuying Li''，更符合现代英语出版物常见顺序。", "naming_policy": "transliteration"}]}, {"entity_id": "02c6ca68267e4cfebb74a10cc1e58530", "candidates": [{"name": "The Ledger (implied)", "rationale": "直译''账本''为''Ledger''，保留''隐含''的提示，符合道具的悬疑属性。", "naming_policy": "literal"}, {"name": "The Hidden Ledger", "rationale": "将''隐含''之意融入名称，译为''The Hidden Ledger''，更符合英语悬疑叙事中道具的命名习惯。", "naming_policy": "cultural_equivalent"}, {"name": "Zhangben (implied)", "rationale": "音译''账本''为''Zhangben''，保留中文原词的神秘感，并注明''隐含''。", "naming_policy": "transliteration"}]}, {"entity_id": "14c18eb154f14e02a4ce1fb37c2fd16f", "candidates": [{"name": "Blue Cloth Bundle", "rationale": "直译''蓝布包袱''，清晰描述物品材质与形态。", "naming_policy": "literal"}, {"name": "Indigo Bundle", "rationale": "选用''Indigo''（靛蓝）替代直译的''Blue''，更具文学色彩和时代感。", "naming_policy": "cultural_equivalent"}, {"name": "Lanbu Baofu", "rationale": "音译''蓝布包袱''，保留中文物品名称的独特文化意象。", "naming_policy": "transliteration"}]}, {"entity_id": "4c9f5b9ef57a49e6a456bdec2f9dc8ce", "candidates": [{"name": "Suspense", "rationale": "''悬疑''在英语类型文学/影视中直接对应''Suspense''。", "naming_policy": "cultural_equivalent"}, {"name": "Mystery Thriller", "rationale": "用''Mystery Thriller''（神秘惊悚）作为更具体的风格等价词，涵盖悬疑与紧张感。", "naming_policy": "cultural_equivalent"}, {"name": "Xuan Yi", "rationale": "音译''悬疑''，作为风格标签保留中文原词特色。", "naming_policy": "transliteration"}]}, {"entity_id": "7bebde2708144371a3f4b9700c46a755", "candidates": [{"name": "On the Run", "rationale": "''逃亡''在英语动作/惊悚类型中常表述为''On the Run''。", "naming_policy": "cultural_equivalent"}, {"name": "Fugitive", "rationale": "用''Fugitive''（逃亡者）作为风格标签，强调人物状态与叙事核心。", "naming_policy": "cultural_equivalent"}, {"name": "Flight", "rationale": "直译''逃亡''为''Flight''（逃跑），简洁且具文学性。", "naming_policy": "literal"}]}, {"entity_id": "8cfda39c5a8f46e29e5d086af1bd61a4", "candidates": [{"name": "Under the Old Locust Tree at Wang Village Entrance", "rationale": "直译地点全称，清晰描述位置（村口、树下）。", "naming_policy": "literal"}, {"name": "The Old Locust Tree, Wangjia Village", "rationale": "调整为英语地点常见表述顺序，以标志物（老槐树）为核心，村庄名作为补充。", "naming_policy": "cultural_equivalent"}, {"name": "Wangjiacun Cunkou, Lao Huaishu Xia", "rationale": "音译完整地点名称，保留中文地名结构特色。", "naming_policy": "transliteration"}]}, {"entity_id": "a769281d8de44c91a2761ae276444d1a", "candidates": [{"name": "Griddle Cakes in Oilpaper Wrapping", "rationale": "直译''油纸包里的烙饼''，准确描述物品材质与内容。", "naming_policy": "literal"}, {"name": "Oilpaper-Wrapped Flatbread", "rationale": "将''烙饼''译为更通用的''Flatbread''，并用连字符结构''Oilpaper-Wrapped''使名称更紧凑，符合英语道具命名习惯。", "naming_policy": "cultural_equivalent"}, {"name": "Youzhibao li de Laobing", "rationale": "音译整个短语，保留中文食物名称的独特性和文化联想。", "naming_policy": "transliteration"}]}, {"entity_id": "b5a3fa41e70a4d09bbdfa7b6b05f05b3", "candidates": [{"name": "Plot-Driven", "rationale": "''剧情''在英语作品分类中常强调''情节驱动''，译为''Plot-Driven''更准确。", "naming_policy": "cultural_equivalent"}, {"name": "Story-Rich", "rationale": "用''Story-Rich''（故事丰富）作为风格标签，突出叙事性。", "naming_policy": "cultural_equivalent"}, {"name": "Dramatic", "rationale": "直译''剧情''的核心含义为''戏剧性的''，简洁通用。", "naming_policy": "literal"}]}]}', '```json
