INSERT INTO public.skill_runs (id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message, retry_count, skill_id, novel_id, chapter_id, input_hash, input_snapshot, status, output_json, raw_response, token_usage, cost_estimate, model_provider_id, model_name) VALUES ('543f43450d4d4270877223fcc010e08d', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 09:45:25.782868+00', '2026-03-01 09:46:01.715537+00', NULL, NULL, NULL, NULL, 0, 'name_localization_suggest', 'novel_b831875078b348ffa5569429fdb4105c', NULL, NULL, '{"era_profile": null, "entity_count": 4, "social_class": null, "culture_profile": null, "target_language": "ja-JP"}', 'succeeded', '{"suggestions": [{"entity_id": "b5a3fa41e70a4d09bbdfa7b6b05f05b3", "rationale": "「剧情」在日语中最直接、最常用的对应词是「ストーリー」，指代作品的情节发展、故事脉络，符合影视/小说内容本地化的通用术语。", "candidates": [{"name": "ストーリー", "rationale": "这是日语中描述故事、情节最普遍和自然的词汇，直接对应「剧情」的核心含义。", "naming_policy": "cultural_equivalent"}, {"name": "プロット", "rationale": "源自英语“plot”，在日语创作领域（尤其是悬疑、推理类）常用来指代更精密的情节设计和结构，比「ストーリー」更具专业感。", "naming_policy": "cultural_equivalent"}, {"name": "筋書き", "rationale": "更偏向书面语或传统说法，指故事的大纲或情节走向，带有一定的古典或文学色彩。", "naming_policy": "cultural_equivalent"}], "recommended_name": "ストーリー"}, {"entity_id": "cd0aaef3eedb4e05a681c76a31daf8ea", "rationale": "「年代」在内容描述中通常指故事发生的时代背景。日语中「時代設定」是更准确、更完整的表达，明确指向作品的时间设定。", "candidates": [{"name": "時代設定", "rationale": "精准对应「年代」在影视/小说语境下的含义，即故事发生的时代，是日语内容介绍的标准术语。", "naming_policy": "cultural_equivalent"}, {"name": "時代背景", "rationale": "强调时代作为故事发生的背景和环境，与「時代設定」意思相近，但更侧重背景的描绘。", "naming_policy": "cultural_equivalent"}, {"name": "舞台（時代）", "rationale": "用「舞台」比喻故事发生的场所，可以特指时间舞台，即时代。这种说法在宣传语或简介中富有画面感。", "naming_policy": "cultural_equivalent"}], "recommended_name": "時代設定"}, {"entity_id": "4c9f5b9ef57a49e6a456bdec2f9dc8ce", "rationale": "「悬疑」类型在日语中直接对应的外来词就是「サスペンス」，这是影视、小说分类和宣传中最通用、最易理解的标签。", "candidates": [{"name": "サスペンス", "rationale": "直接音译自“suspense”，是日语中定义该类型作品最核心、最无歧义的词汇，观众/读者认知度最高。", "naming_policy": "cultural_equivalent"}, {"name": "ミステリー", "rationale": "音译自“mystery”，常与「サスペンス」并用或互换，但更侧重于谜题、推理和解谜的过程。", "naming_policy": "cultural_equivalent"}, {"name": "スリラー", "rationale": "音译自“thriller”，强调紧张、刺激和惊悚感，与「逃亡」风格结合时可能更贴切。", "naming_policy": "cultural_equivalent"}], "recommended_name": "サスペンス"}, {"entity_id": "7bebde2708144371a3f4b9700c46a755", "rationale": "「逃亡」作为一种剧情风格或主题，在日语中常表述为「逃亡劇」，指以逃亡为主线展开的戏剧性故事，比单独「逃亡」一词更符合内容分类的语境。", "candidates": [{"name": "逃亡劇", "rationale": "在「逃亡」后加上「劇」，精准概括了以逃亡为核心情节的作品类型，是日语中常见的分类表述。", "naming_policy": "cultural_equivalent"}, {"name": "逃避行", "rationale": "更侧重“逃离并持续行动”的过程，带有文学性和叙事感，常用于描述故事中的一段逃亡旅程。", "naming_policy": "cultural_equivalent"}, {"name": "チェイスもの", "rationale": "口语化表达，直译为“追逐系作品”，强调追与逃的对抗和动作场面，更具类型片的通俗色彩。", "naming_policy": "cultural_equivalent"}], "recommended_name": "逃亡劇"}]}', '```json
