                },
                {
                    "name": "プロット",
                    "naming_policy": "cultural_equivalent",
                    "rationale": "源自英语“plot”，在日语创作领域（尤其是悬疑、推理类）常用来指代更精密的情节设计和结构，比「ストーリー」更具专业感。"
                },
                {
                    "name": "筋書き",
