INSERT INTO public.skill_runs (id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message, retry_count, skill_id, novel_id, chapter_id, input_hash, input_snapshot, status, output_json, raw_response, token_usage, cost_estimate, model_provider_id, model_name) VALUES ('7a7c5cf22f104e5d8ba5cec75c84d504', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-03-01 10:32:28.87632+00', '2026-03-01 10:32:35.378663+00', NULL, NULL, NULL, NULL, 0, 'translation_run', 'novel_b831875078b348ffa5569429fdb4105c', NULL, '36a8c6f0d4f3d6051614216589458238', '{"project_id": "b99582ef92864d0dbc119d4ac347b087", "block_count": 1, "target_language": "en-US"}', 'succeeded', '{"results": [{"id": "3f62181673214e208e3f80a7bfdc6b3c", "translated_text": "**Wang Mazi** (real name Wang Mazi (birth name Wang Youfu)) walked from the end of the dirt road, his steps heavy and hurried. He was roughly in his early forties, tall and lean, with a slightly hunched back, wearing a faded navy blue cotton jacket whose cuffs were frayed. The few pockmarks on his face were indistinct in the dim light, but his eyes were exceptionally bright—the kind of gaze possessed by someone long accustomed to traveling and worldly experience, yet now mixed with weariness, anxiety, and a trace of barely perceptible vigilance."}], "warnings": 0, "translated": 1}', '```json
[
  {
    "id": "3f62181673214e208e3f80a7bfdc6b3c",
    "translated_text": "**Wang Mazi** (real name {{CHAR:326e160a0f_326e16}}) walked from the end of the dirt road, his steps heavy and hurried. He was roughly in his early forties, tall and lean, with a slightly hunched back, wearing a faded navy blue cotton jacket whose cuffs were frayed. The few pockmarks on his face were indistinct in the dim light, but his eyes were exceptionally bright—the kind of gaze possessed by someone long accustomed to traveling and worldly experience, yet now mixed with weariness, anxiety, and a trace of barely perceptible vigilance."
  }
]
```', NULL, NULL, 'provider_c86aa37930fd4a56a1d0cf549a62e2a0', NULL);
