INSERT INTO public.story_events (chapter_id, event_no, summary, structured_json, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES ('chapter_904bae811e7e4e2c9a124bdb12f65be6', 1, '深夜子时三刻，王麻子（本名王有福）携怀孕的妻子李秀英，从省城匆忙潜回王家村。两人在村口老槐树下停驻，王麻子神情警惕，不断回望来路，确认无人跟踪。他向妻子解释必须连夜回村的原因：他们在省城可能卷入某事，带走了一本重要的“账本”，担心天亮后城里的人会追查到村里。王麻子叮嘱妻子对外统一口径，只说在省城做小买卖赔了，绝口不提账本。正当两人稍作休息时，村中由远及近传来此起彼伏的狗吠声，令王麻子瞬间紧张起来。', '{"title": "王麻子携孕妻深夜潜回村庄", "participants": ["王有福", "李秀英"]}', 0, 'sev_b47d4264e0bf4b1183b870a4cd8654f1', 'default', 'default', NULL, NULL, NULL, 'v1', NULL, '2026-02-28 19:20:37.808762+00', '2026-02-28 19:20:37.808764+00', NULL, NULL, NULL, NULL);


