INSERT INTO public.workflow_events (run_id, job_id, stage, event_type, event_version, producer, occurred_at, payload_json, error_json, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES (NULL, NULL, NULL, 'audit.recorded', '1.0', 'studio_api', '2026-02-28 17:56:36.498053+00', '{"note": "编辑器保存", "action": "chapter.revision", "editor": "editor", "chapter_id": "chapter_904bae811e7e4e2c9a124bdb12f65be6", "previous_markdown_text": "夜黑风高王麻子在风尘仆仆带着老婆回乡"}', NULL, 0, 'evt_225f273eca714b4fa82c8957', 'default', 'default', 'tr_ch_ad9659f5a8fe', 'cr_ch_2cc1dfc72391', 'idem_revision_chapter_904bae811e7e4e2c9a124bdb12f65be6_b01066fb', 'v1', NULL, '2026-02-28 17:56:36.503094+00', '2026-02-28 17:56:36.503102+00', NULL, NULL, NULL, NULL);
INSERT INTO public.workflow_events (run_id, job_id, stage, event_type, event_version, producer, occurred_at, payload_json, error_json, retry_count, id, tenant_id, project_id, trace_id, correlation_id, idempotency_key, version, deleted_at, created_at, updated_at, created_by, updated_by, error_code, error_message) VALUES (NULL, NULL, NULL, 'audit.recorded', '1.0', 'studio_api', '2026-02-28 17:56:45.12176+00', '{"note": "编辑器保存", "action": "chapter.revision", "editor": "editor", "chapter_id": "chapter_904bae811e7e4e2c9a124bdb12f65be6", "previous_markdown_text": "# 王麻子回村\n\n## 场景一：村口老槐树\n\n**时间**：深夜，约莫子时三刻  \n**地点**：王家村村口，老槐树下  \n**天气**：北风呼啸，乌云蔽月，偶有零星雨点砸落  \n\n---\n\n### 【环境描写】\n\n村口那棵百年老槐树在夜风中张牙舞爪，枯枝如鬼爪般摇曳，投下破碎晃动的阴影。树身上贴着的褪色春联残片被风吹得哗啦作响，像是什么人在低声絮语。通往村里的土路坑洼不平，积水映不出半点星光，只有远处零星几户人家窗棂透出昏黄油灯的光晕，在浓墨般的夜色中颤抖。\n\n北风卷着沙土和枯叶打旋儿，空气中弥漫着潮湿的泥土味和远处牲口棚传来的淡淡腥臊。更远处，黑黢黢的山峦轮廓如巨兽匍匐，沉默地注视着这个即将被打破宁静的村庄。\n\n---\n\n### 【人物出场】\n\n**王麻子**（本名王有福）从土路尽头走来，脚步沉重而急促。他约莫四十出头，身材瘦高，背微微佝偻，穿着一件洗得发白的藏青色棉袄，袖口磨出了毛边。脸上那几颗麻子在昏暗光线下看不真切，但那双眼睛却异常明亮——那是常年在外奔波、见惯世面的人才有的眼神，此刻却混杂着疲惫、焦虑和一丝不易察觉的警惕。\n\n他左手提着一个鼓囊囊的蓝布包袱，右手紧紧攥着身边女人的手腕。\n\n**李秀英**（王麻子妻子）被他拽得踉踉跄跄。她比王麻子年轻七八岁，面容清秀却憔悴，眼角细纹在阴影中格外明显。她裹着一件半旧的碎花棉袄，头发用木簪草草绾起，几缕碎发被汗水黏在额角。她不时回头张望，嘴唇抿得发白，另一只手无意识地护着小腹——那里微微隆起，约莫四五个月的身孕。\n\n---\n\n### 【动作与情绪细节】\n\n**王麻子**的脚步在槐树下骤然停住。\n\n他松开妻子的手腕，转身望向来的方向。土路尽头空无一人，只有风声呜咽。但他还是眯起眼睛看了许久，喉结上下滚动，像是在确认什么。汗水顺着他的鬓角滑下，在颧骨处留下一道湿痕。\n\n“没人跟来。”他低声说，更像是在说服自己。声音沙哑，带着长途跋涉后的干涩。\n\n**李秀英**靠上槐树粗糙的树干，喘着气，胸口起伏。她抬手抹了把脸，不知是雨水还是泪水。\n\n“有福……”她声音发颤，“咱非得这时候回来？天亮了再进村不行吗？”\n\n王麻子没立刻回答。他蹲下身，从包袱里摸出一个油纸包，里面是半块硬邦邦的烙饼。他掰了一小块递给妻子，自己啃着更小的那块，咀嚼得很慢，眼睛始终没离开村口那条路。\n\n“等不到天亮。”他终于开口，饼屑从嘴角掉下，“城里那些人……要是发现账本不见了，头一个就找这儿来。”\n\n“可村里人……”李秀英接过饼，却没吃，手指无意识地捏着饼边，“他们要是问起这些年……”\n\n“就说在省城做小买卖，赔了。”王麻子打断她，语气斩钉截铁。他站起身，拍了拍裤腿上的土，动作里透着一股狠劲儿，“记住，秀英，咱什么都不知道。账本的事，一个字都不能提。”\n\n李秀英低下头，手指抚上小腹，轻轻摩挲。这个动作被王麻子看在眼里，他眼神软了一瞬，但随即又硬起来。\n\n“为了孩子。”他补了一句，声音压低，“得让他生在干净地方。”\n\n---\n\n### 【冲突铺垫】\n\n就在这时，远处传来狗吠。\n\n不是一家，而是此起彼伏，从村东头一路响过来，像涟漪般在夜色中扩散。王麻子浑身一僵，猛地将妻子拉到槐树阴影"}', NULL, 0, 'evt_1d5e4525d4fa4a39a64598b6', 'default', 'default', 'tr_ch_ad9659f5a8fe', 'cr_ch_2cc1dfc72391', 'idem_revision_chapter_904bae811e7e4e2c9a124bdb12f65be6_ce3bae43', 'v1', NULL, '2026-02-28 17:56:45.122317+00', '2026-02-28 17:56:45.12232+00', NULL, NULL, NULL, NULL);
